// PLUGIN : KIT MONNAIE (V14 - Proportions Mathématiques Corrigées)
// ==========================================
registerPlugin('moneyTool', 'Maths - Numérique', {
    widgetEl: null,
    currentStamp: null,
    scale: 0.4, // Échelle globale pour que ça tienne bien sur l'écran

    init: function () {
        const btn = document.createElement('button');
        btn.className = 'btn'; btn.dataset.mode = 'money'; btn.title = 'Kit Monnaie';
        btn.innerHTML = `<svg viewBox="0 0 24 24" class="stroke-icon" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><rect x="2" y="6" width="20" height="12" rx="2"/><circle cx="12" cy="12" r="2"/><path d="M6 12h.01M18 12h.01"/></svg>`;
        document.getElementById('plugins-grid').appendChild(btn);

        btn.addEventListener('click', (e) => {
            e.stopPropagation();
            this.toggleWidget();
        });

        this.createWidget();
    },

    createWidget: function () {
        this.widgetEl = document.createElement('div');
        this.widgetEl.id = 'money-widget';
        this.widgetEl.style.cssText = "display:none; position:fixed; left:120px; top:120px; width:220px; background:#fff; border-radius:12px; box-shadow:0 8px 24px rgba(0,0,0,0.2); z-index:10000; padding:15px; border:1px solid #dfe6e9; font-family:sans-serif;";

        this.widgetEl.innerHTML = `
            <div style="font-weight:900; margin-bottom:12px; font-size:13px; display:flex; justify-content:space-between; align-items:center; color:#2d3436;">
                Kit Monnaie <span style="cursor:pointer; font-size:16px;" onclick="MoneyPlugin.widgetEl.style.display='none'">✕</span>
            </div>
            <select id="money-select" class="dw-select" style="margin-bottom:0; cursor:pointer;">
                <option value="1c">🟡 1 ct</option><option value="2c">🟡 2 ct</option><option value="5c">🟡 5 ct</option>
                <option value="10c">🟠 10 ct</option><option value="20c">🟠 20 ct</option><option value="50c">🟠 50 ct</option>
                <option value="1e" selected>🪙 1 €</option><option value="2e">🪙 2 €</option>
                <option value="5b">💵 5 €</option><option value="10b">💵 10 €</option><option value="20b">💵 20 €</option>
                <option value="50b">💵 50 €</option><option value="100b">💵 100 €</option>
                <option value="200b">💵 200 €</option><option value="500b">💵 500 €</option>
            </select>
            <label class="dw-label" style="margin-top:10px;">Taille globale :</label>
            <input type="range" id="money-scale" min="0.2" max="0.8" step="0.1" value="${this.scale}" style="width:100%;">
        `;
        document.body.appendChild(this.widgetEl);
        window.MoneyPlugin = this;

        this.widgetEl.querySelector('#money-select').addEventListener('change', () => this.updateStamp());
        this.widgetEl.querySelector('#money-scale').addEventListener('input', (e) => {
            this.scale = parseFloat(e.target.value);
            this.updateStamp();
        });
    },

    toggleWidget: function () {
        if (!this.widgetEl) this.createWidget();
        const isVisible = this.widgetEl.style.display === 'block';
        this.widgetEl.style.display = isVisible ? 'none' : 'block';
        if (!isVisible) this.updateStamp();
        else if (typeof setMode === 'function') setMode('pointer');
    },

    updateStamp: function () {
        const type = document.getElementById('money-select').value;
        if (typeof createStampFromSVG === 'function') {
            createStampFromSVG(this.getMoneySVG(type), (stamp) => {
                this.currentStamp = stamp;
                if (typeof setMode === 'function') setMode('money');
            });
        }
    },

    getMoneySVG: function (type) {
        const s = this.scale;
        const copper = { fill: '#e67e22', border: '#d35400', text: '#fff' };
        const gold = { fill: '#f1c40f', border: '#f39c12', text: '#2d3436' };
        const silver = { fill: '#ecf0f1', border: '#bdc3c7', text: '#2d3436' };

        // Diamètre de référence pour une pièce = 60px
        const drawCoin = (diam, outer, inner, text, isBicolor = false) => {
            const size = diam * s;
            return `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 ${size} ${size}" width="${size}" height="${size}">
                <circle cx="${size / 2}" cy="${size / 2}" r="${(size / 2) - (2 * s)}" fill="${outer.fill}" stroke="${outer.border}" stroke-width="${2 * s}"/>
                ${isBicolor ? `<circle cx="${size / 2}" cy="${size / 2}" r="${size * 0.35}" fill="${inner.fill}" stroke="${inner.border}" stroke-width="${1.5 * s}"/>` : ''}
                <text x="${size / 2}" y="${size / 2}" font-family="sans-serif" font-weight="bold" font-size="${size * 0.35}" fill="${isBicolor ? inner.text : outer.text}" text-anchor="middle" dominant-baseline="central">${text}</text>
            </svg>`;
        };

        // Billet : Hauteur = 2.5 * diamètre de la pièce (60 * 2.5 = 150px)
        const drawBill = (color, val, widthRatio) => {
            const baseH = 150 * s;
            const h = baseH;
            const w = (baseH * 1.8) * widthRatio; // Aspect ratio ~1.8
            return `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 ${w} ${h}" width="${w}" height="${h}">
                <rect width="${w}" height="${h}" rx="${10 * s}" fill="${color}" stroke="#2d3436" stroke-width="${3 * s}"/>
                <rect x="${10 * s}" y="${10 * s}" width="${w - 20 * s}" height="${h - 20 * s}" rx="${5 * s}" fill="#fff" fill-opacity="0.8" stroke="#2d3436" stroke-width="${2 * s}"/>
                <text x="${w / 2}" y="${h / 2}" font-family="sans-serif" font-weight="bold" font-size="${40 * s}" fill="#2d3436" text-anchor="middle" dominant-baseline="central">${val} €</text>
            </svg>`;
        };

        const map = {
            '1c': () => drawCoin(60, copper, null, "1 ct"),
            '2c': () => drawCoin(64, copper, null, "2 ct"),
            '5c': () => drawCoin(68, copper, null, "5 ct"),
            '10c': () => drawCoin(66, gold, null, "10 ct"),
            '20c': () => drawCoin(70, gold, null, "20 ct"),
            '50c': () => drawCoin(74, gold, null, "50 ct"),
            '1e': () => drawCoin(72, gold, silver, "1 €", true),
            '2e': () => drawCoin(76, silver, gold, "2 €", true),
            '5b': () => drawBill('#b2bec3', "5", 0.9),
            '10b': () => drawBill('#ff7675', "10", 1.0),
            '20b': () => drawBill('#74b9ff', "20", 1.1),
            '50b': () => drawBill('#e17055', "50", 1.2),
            '100b': () => drawBill('#55efc4', "100", 1.3),
            '200b': () => drawBill('#ffeaa7', "200", 1.4),
            '500b': () => drawBill('#a29bfe', "500", 1.5)
        };
        return map[type]();
    },

    onDraw: function (ctx) {
        if (typeof mode !== 'undefined' && mode === 'money' && this.currentStamp && typeof mouseLogicalPos !== 'undefined') {
            ctx.globalAlpha = 0.7;
            ctx.drawImage(this.currentStamp.img, mouseLogicalPos.x - this.currentStamp.w / 2, mouseLogicalPos.y - this.currentStamp.h / 2);
            ctx.globalAlpha = 1.0;
        }
    },

    onPointerDown: function (rawPos) {
        if (typeof mode !== 'undefined' && mode === 'money' && this.currentStamp) {
            if (typeof imageCache !== 'undefined') imageCache[this.currentStamp.src] = this.currentStamp.img;
            images.push({
                id: nextId++,
                x: rawPos.x - this.currentStamp.w / 2, y: rawPos.y - this.currentStamp.h / 2,
                w: this.currentStamp.w, h: this.currentStamp.h,
                cx: 0, cy: 0, cw: this.currentStamp.w, ch: this.currentStamp.h,
                src: this.currentStamp.src, z: globalZ++,
                pluginData: { id: 'moneyTool' }
            });
            if (typeof saveState === 'function') saveState();
            if (typeof draw === 'function') draw();
            return true;
        }
        return false;
    },

    closeWidget: function () {
        if (this.widgetEl) this.widgetEl.style.display = 'none';
        if (typeof setMode === 'function') setMode('pointer');
    }
});

