            bulb: `<svg viewBox="0 0 40 40" style="${svgStyle}"><circle cx="20" cy="20" r="10" fill="none" stroke="#2c3e50" stroke-width="2"/><path d="M13 13 L27 27 M13 27 L27 13" stroke="#2c3e50" stroke-width="2"/></svg>`,
            switch: `<svg viewBox="0 0 40 40" style="${svgStyle}"><circle cx="12" cy="20" r="2" fill="#2c3e50"/><circle cx="28" cy="20" r="2" fill="#2c3e50"/><line x1="12" y1="20" x2="26" y2="14" stroke="#2c3e50" stroke-width="2"/></svg>`,
            resistor: `<svg viewBox="0 0 40 40" style="${svgStyle}"><rect x="10" y="15" width="20" height="10" fill="none" stroke="#2c3e50" stroke-width="2"/></svg>`,
            capacitor: `<svg viewBox="0 0 40 40" style="${svgStyle}"><line x1="16" y1="10" x2="16" y2="30" stroke="#2c3e50" stroke-width="2"/><line x1="24" y1="10" x2="24" y2="30" stroke="#2c3e50" stroke-width="2"/></svg>`,
