// 17. NOUVEAU : PORTÉE MUSICALE (Tablatures + Largeur)
// ==========================================
// 17. PORTÉE MUSICALE (Tablatures + Largeur)
// ==========================================
registerPlugin('musicStaffTool', 'Musique', {
    currentStamp: null, currentArgs: null,
    init: function () {
        const btn = document.createElement('button'); btn.className = 'btn'; btn.dataset.mode = 'musicStaff'; btn.title = 'Portée Musicale';
        btn.innerHTML = `<svg viewBox="0 0 24 24" class="stroke-icon" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round"><path d="M9 18V5l12-2v13"/><circle cx="6" cy="18" r="3"/><circle cx="18" cy="16" r="3"/></svg>`;
        document.getElementById('plugins-grid').appendChild(btn);

        btn.addEventListener('click', (e) => {
            document.querySelectorAll('.btn').forEach(b => b.classList.remove('active')); btn.classList.add('active'); setMode('musicStaff');
            openCustomPrompt("Portée Musicale", [
                {
                    type: 'select', label: "Type", value: "sol", options: [
                        { value: 'sol', label: 'Clé de Sol' },
                        { value: 'fa', label: 'Clé de Fa' },
                        { value: 'tab6', label: 'Tab. Guitare (6)' },
                        { value: 'tab7', label: 'Tab. Guitare (7)' },
                        { value: 'tab4', label: 'Tab. Basse (4)' },
                        { value: 'tab5', label: 'Tab. Basse (5)' },
                        { value: 'none', label: 'Simple (5 lignes)' }
                    ]
                },
                { type: 'select', label: "Largeur", value: "1200", options: [{ value: '800', label: 'Petite (800px)' }, { value: '1200', label: 'Page (1200px)' }, { value: '2000', label: 'Très longue (2000px)' }] },
                { type: 'color', label: "Couleur", value: "#2d3436" }
            ], (res) => this.generateSVG(res),
                (res) => { createStampFromSVG(this.generateSVG(res, true), (stamp) => { this.currentStamp = stamp; this.currentArgs = res; showToast("📌 Posez la portée !"); }); });
            e.stopPropagation();
        });
    },
    edit: function (imgObj) {
        const args = imgObj.pluginData.args;
        openCustomPrompt("Modifier la Portée", [
            {
                type: 'select', label: "Type", value: args[0], options: [
                    { value: 'sol', label: 'Clé de Sol' },
                    { value: 'fa', label: 'Clé de Fa' },
                    { value: 'tab6', label: 'Tab. Guitare (6)' },
                    { value: 'tab7', label: 'Tab. Guitare (7)' },
                    { value: 'tab4', label: 'Tab. Basse (4)' },
                    { value: 'tab5', label: 'Tab. Basse (5)' },
                    { value: 'none', label: 'Simple (5 lignes)' }
                ]
            },
            { type: 'select', label: "Largeur", value: args[1], options: [{ value: '800', label: 'Petite' }, { value: '1200', label: 'Page' }, { value: '2000', label: 'Très longue' }] },
            { type: 'color', label: "Couleur", value: args[2] }
        ], (res) => this.generateSVG(res),
            (res) => { createStampFromSVG(this.generateSVG(res, true), (stamp) => { imgObj.src = stamp.src; imgObj.w = stamp.w; imgObj.h = stamp.h; imgObj.cw = stamp.w; imgObj.ch = stamp.h; imgObj.pluginData.args = res; draw(); saveState(); }); });
    },
    generateSVG: function (res, isExport = false) {
        let type = res[0]; let wOption = parseInt(res[1]) || 1200; let color = res[2] || '#2d3436';
        let w = isExport ? wOption : 400; let h = isExport ? 150 : 75;
        let svg = `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 ${w} ${h}" width="${isExport ? w : '100%'}" height="${isExport ? h : '100%'}">`;
        let space = isExport ? 20 : 10;

        let linesCount = 5;
        // Détecte automatiquement le nombre de cordes (4, 5, 6 ou 7)
        if (type.startsWith('tab')) linesCount = parseInt(type.replace('tab', ''));

        let startY = isExport ? 30 : 15;
        let staffHeight = (linesCount - 1) * space;

        for (let i = 0; i < linesCount; i++) {
            svg += `<line x1="0" y1="${startY + i * space}" x2="${w}" y2="${startY + i * space}" stroke="${color}" stroke-width="2"/>`;
        }

        if (type === 'sol') {
            svg += `<text x="${isExport ? 20 : 10}" y="${startY + space * 3 + (isExport ? 15 : 8)}" font-size="${h * 0.8}" font-family="serif" fill="${color}">𝄞</text>`;
        } else if (type === 'fa') {
            svg += `<text x="${isExport ? 20 : 10}" y="${startY + space * 2 + (isExport ? 10 : 5)}" font-size="${h * 0.7}" font-family="serif" fill="${color}">𝄢</text>`;
        } else if (type.startsWith('tab')) {
            // NOUVEAU : Centrage dynamique selon la hauteur réelle de la portée !
            let cx = isExport ? 25 : 12.5;
            let cy = startY + staffHeight / 2;
            let delta = staffHeight / 3.2; // Espacement vertical des lettres ajusté au nombre de cordes
            let fontSize = isExport ? 26 : 13;
            let textStyles = `font-size="${fontSize}" font-family="sans-serif" font-weight="bold" fill="${color}" text-anchor="middle" dominant-baseline="central"`;

            svg += `<text x="${cx}" y="${cy - delta}" ${textStyles}>T</text>`;
            svg += `<text x="${cx}" y="${cy}" ${textStyles}>A</text>`;
            svg += `<text x="${cx}" y="${cy + delta}" ${textStyles}>B</text>`;
            svg += `<line x1="${isExport ? 50 : 25}" y1="${startY}" x2="${isExport ? 50 : 25}" y2="${startY + staffHeight}" stroke="${color}" stroke-width="2"/>`; // Barre verticale
        }
        return svg + `</svg>`;
    },
    onDraw: function (ctx) { if (mode === 'musicStaff' && this.currentStamp && mouseLogicalPos) { ctx.globalAlpha = 0.5; ctx.drawImage(this.currentStamp.img, mouseLogicalPos.x - this.currentStamp.w / 2, mouseLogicalPos.y - this.currentStamp.h / 2); ctx.globalAlpha = 1.0; } },
    onPointerDown: function (rawPos) { if (mode === 'musicStaff' && this.currentStamp) { images.push({ id: nextId++, x: rawPos.x - this.currentStamp.w / 2, y: rawPos.y - this.currentStamp.h / 2, w: this.currentStamp.w, h: this.currentStamp.h, cx: 0, cy: 0, cw: this.currentStamp.w, ch: this.currentStamp.h, src: this.currentStamp.src, z: globalZ++, pluginData: { id: 'musicStaffTool', args: this.currentArgs } }); saveState(); setMode('pointer'); this.currentStamp = null; return true; } return false; }
});


// ==========================================
// 19. CARTES GÉOGRAPHIQUES (Version de Débogage Ultime)
// ==========================================
// ==========================================
// 19. CARTES GÉOGRAPHIQUES (Version Infaillible)
// ==========================================
// ==========================================
// 19. CARTES GÉOGRAPHIQUES (Intégration Native Parfaite)
// ==========================================
registerPlugin('mapTool', 'Histoire-Géographie', {
    currentStamp: null, currentArgs: null,

    // Le constructeur parfait de SVG
    fetchMap: function (code, color, callback) {
        fetch(`https://raw.githubusercontent.com/djaiss/mapsicon/master/all/${code}/vector.svg`)
            .then(r => { if (!r.ok) throw new Error("HTTP " + r.status); return r.text(); })
            .then(svgText => {
                let svgMatch = svgText.match(/<svg[^>]*>([\s\S]*?)<\/svg>/i);
                let innerContent = svgMatch ? svgMatch[1] : "";
                let viewBoxMatch = svgText.match(/viewBox="([^"]+)"/i);
                let viewBox = viewBoxMatch ? viewBoxMatch[1] : "0 0 1024 1024";

                // Nettoyage et coloration
                innerContent = innerContent.replace(/fill="[^"]*"/ig, "");
                innerContent = innerContent.replace(/stroke="[^"]*"/ig, "");

                let cleanSvg = `<svg xmlns="http://www.w3.org/2000/svg" width="400" height="400" viewBox="${viewBox}">
                    <g fill="${color}" stroke="#2d3436" stroke-width="10">
                        ${innerContent}
                    </g>
                </svg>`;
                callback(cleanSvg);
            }).catch(err => {
                //  console.error("[MAP] Erreur réseau:", err);
                callback(null);
            });
    },

    init: function () {
        const btn = document.createElement('button'); btn.className = 'btn'; btn.dataset.mode = 'map'; btn.title = 'Cartes Géographiques';
        btn.innerHTML = `<svg viewBox="0 0 24 24" class="stroke-icon" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round"><polygon points="3 6 9 3 15 6 21 3 21 18 15 21 9 18 3 21"/><line x1="9" y1="3" x2="9" y2="18"/><line x1="15" y1="6" x2="15" y2="21"/></svg>`;
        document.getElementById('plugins-grid').appendChild(btn);

        // TOUCHE ECHAP POUR ANNULER
        document.addEventListener('keydown', (e) => {
            if (e.key === 'Escape' && mode === 'map') {
                this.currentStamp = null;
                setMode('pointer');
                showToast("Tampon annulé");
                draw();
            }
        });

        btn.addEventListener('click', (e) => {
            document.querySelectorAll('.btn').forEach(b => b.classList.remove('active')); btn.classList.add('active');

            openCustomPrompt("Cartes du Monde", [
                {
                    type: 'select', label: "Pays", value: "fr", options: [
                        { value: 'fr', label: 'France' }, { value: 'gb', label: 'Royaume-Uni' }, { value: 'de', label: 'Allemagne' },
                        { value: 'es', label: 'Espagne' }, { value: 'it', label: 'Italie' }, { value: 'us', label: 'États-Unis' },
                        { value: 'cn', label: 'Chine' }, { value: 'jp', label: 'Japon' }, { value: 'br', label: 'Brésil' },
                        { value: 'za', label: 'Afrique du Sud' }, { value: 'au', label: 'Australie' }
                    ]
                },
                { type: 'color', label: "Couleur", value: "#0984e3" }
            ],
                (res) => { // Prévisualisation
                    const previewBox = document.getElementById('custom-prompt-preview');
                    if (previewBox) previewBox.innerHTML = '<div style="text-align:center; padding:20px;">Chargement...</div>';
                    this.fetchMap(res[0], res[1], (svg) => {
                        if (svg && previewBox) previewBox.innerHTML = svg.replace(/width="400" height="400"/, 'width="100%" height="100%"');
                    });
                    return "";
                },
                (res) => { // Validation
                    showToast("⏳ Chargement de la carte...");
                    this.fetchMap(res[0], res[1], (svg) => {
                        if (svg) {
                            const img = new Image();
                            img.onload = () => {
                                this.currentStamp = { img: img, src: img.src, w: 400, h: 400 };
                                this.currentArgs = res;
                                setMode('map');
                                showToast("📌 Tampon prêt ! (Échap pour annuler)");
                                draw(); // Force le premier affichage
                            };
                            img.src = "data:image/svg+xml;charset=utf-8," + encodeURIComponent(svg);
                        } else showToast("❌ Erreur de réseau");
                    });
                });
            e.stopPropagation();
        });
    },

    edit: function (imgObj) {
        const args = imgObj.pluginData.args;
        openCustomPrompt("Modifier la Carte", [
            { type: 'select', label: "Pays", value: args[0], options: [{ value: 'fr', label: 'France' }, { value: 'gb', label: 'UK' }, { value: 'de', label: 'Allemagne' }, { value: 'es', label: 'Espagne' }] },
            { type: 'color', label: "Couleur", value: args[1] }
        ],
            (res) => {
                const previewBox = document.getElementById('custom-prompt-preview');
                this.fetchMap(res[0], res[1], (svg) => {
                    if (svg && previewBox) previewBox.innerHTML = svg.replace(/width="400" height="400"/, 'width="100%" height="100%"');
                });
                return "Chargement...";
            },
            (res) => {
                this.fetchMap(res[0], res[1], (svg) => {
                    if (svg) {
                        const img = new Image();
                        img.onload = () => {
                            imgObj.src = img.src; imgObj.w = 400; imgObj.h = 400; imgObj.cw = 400; imgObj.ch = 400; imgObj.pluginData.args = res;
                            draw(); saveState();
                        };
                        img.src = "data:image/svg+xml;charset=utf-8," + encodeURIComponent(svg);
                    }
                });
            });
    },

    // LA CLÉ EST LÀ : on force le rafraîchissement au mouvement de la souris
    onPointerMove: function (rawPos, e) {
        if (mode === 'map' && this.currentStamp) {
            // Mémorisation de la position pour le fantôme
            mouseLogicalPos = { x: rawPos.x, y: rawPos.y };
            draw(); // Réveille le tableau !
            return false; // On renvoie false pour ne pas bloquer le reste des écouteurs
        }
        return false;
    },

    onDraw: function (ctx) {
        if (mode === 'map' && this.currentStamp && typeof mouseLogicalPos !== 'undefined' && mouseLogicalPos) {
            ctx.globalAlpha = 0.5;
            ctx.drawImage(this.currentStamp.img, mouseLogicalPos.x - 200, mouseLogicalPos.y - 200, 400, 400);
            ctx.globalAlpha = 1.0;
        }
    },

    onPointerDown: function (rawPos) {
        // console.log("[DEBUG] Clic détecté. Mode actuel :", mode);

        // On vérifie si on est bien dans le mode du plugin et qu'on a un tampon
        if (this.currentStamp) {
            //   console.log("[DEBUG] Tampon trouvé, tentative de pose...");

            // 1. Mise en cache forcée (La clé du problème)
            if (typeof imageCache !== 'undefined') {
                imageCache[this.currentStamp.src] = this.currentStamp.img;
                //     console.log("[DEBUG] Image injectée dans imageCache");
            }

            // 2. Enregistrement
            images.push({
                id: nextId++,
                x: rawPos.x - this.currentStamp.w / 2,
                y: rawPos.y - this.currentStamp.h / 2,
                w: this.currentStamp.w, h: this.currentStamp.h,
                cx: 0, cy: 0,
                cw: this.currentStamp.w, ch: this.currentStamp.h,
                src: this.currentStamp.src,
                z: globalZ++,
                pluginData: { id: 'probatree', args: this.currentTreeData } // ou 'trafficLightTool'
            });

            // 3. Nettoyage et mise à jour
            this.currentStamp = null;
            saveState();
            setMode('pointer');

            // 4. Force le redessin
            draw();
            //    console.log("[DEBUG] Tampon posé avec succès.");
            return true;
        }
        //  console.log("[DEBUG] Aucun tampon actif, clic ignoré par le plugin.");
        return false;
    }
});

registerPlugin('trafficLightTool', 'Outils Profs', {
    currentStamp: null, currentArgs: null,

    // Liste combinée des feux et des panneaux pour les menus déroulants
    signOptions: [
        { value: 'light_green', label: '🟢 Feu Vert (Autorisé)' },
        { value: 'light_orange', label: '🟠 Feu Orange (Chuchotement)' },
        { value: 'light_red', label: '🔴 Feu Rouge (Silence)' },
        { value: 'light_off', label: '⚫ Feu Éteint' },
        { value: 'sign_stop', label: '🛑 Panneau STOP' },
        { value: 'sign_warning', label: '⚠️ Panneau Attention' },
        { value: 'sign_forbidden', label: '⛔ Sens Interdit' },
        { value: 'sign_yield', label: '🔻 Céder le passage' },
        { value: 'sign_silence', label: '🔇 Panneau "Chut !"' }
    ],

    init: function () {
        const grid = document.getElementById('plugins-grid'); if (!grid) return;
        const btn = document.createElement('button'); btn.className = 'btn'; btn.dataset.mode = 'traffic';
        btn.title = 'Signalisation (Feux & Panneaux)';
        btn.innerHTML = `<svg viewBox="0 0 24 24" class="stroke-icon" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">
            <rect x="5" y="2" width="14" height="20" rx="4" ry="4"/>
            <circle cx="12" cy="7" r="2.5"/><circle cx="12" cy="12" r="2.5"/><circle cx="12" cy="17" r="2.5"/>
        </svg>`;
        grid.appendChild(btn);

        btn.addEventListener('click', (e) => {
            document.querySelectorAll('#bar-tools .btn, #plugins-grid .btn').forEach(b => b.classList.remove('active'));
            btn.classList.add('active');
            if (typeof setMode === 'function') setMode('traffic');

            openCustomPrompt("Signalisation de Classe", [
                { type: 'select', label: "Modèle", value: "light_green", options: this.signOptions },
                { type: 'select', label: "Style (Feux)", value: "neon", options: [{ value: 'neon', label: 'Moderne (Brillant)' }, { value: 'classic', label: 'Classique' }] }
            ],
                (res) => this.genSVG(res),
                (res) => {
                    this.createImage(this.genSVG(res, true), (s) => {
                        this.currentStamp = s; this.currentArgs = res;
                        if (typeof showToast === 'function') showToast("📌 Cliquez pour poser le panneau !");
                        if (typeof draw === 'function') draw();
                    });
                });
            e.stopPropagation();
        });
    },

    edit: function (imgObj) {
        openCustomPrompt("Modifier la Signalisation", [
            { type: 'select', label: "Modèle", value: imgObj.pluginData.args[0], options: this.signOptions },
            { type: 'select', label: "Style (Feux)", value: imgObj.pluginData.args[1], options: [{ value: 'neon', label: 'Moderne (Brillant)' }, { value: 'classic', label: 'Classique' }] }
        ],
            (res) => this.genSVG(res),
            (res) => {
                this.createImage(this.genSVG(res, true), (s) => {
                    imgObj.src = s.src; imgObj.w = s.w; imgObj.h = s.h; imgObj.cw = s.w; imgObj.ch = s.h;
                    imgObj.pluginData.args = res;

                    // 🔧 CORRECTION CACHE : On met à jour l'image en cache pour l'édition !
                    if (typeof imageCache !== 'undefined') imageCache[s.src] = s.img;

                    if (typeof draw === 'function') draw();
                    if (typeof saveState === 'function') saveState();
                });
            });
    },

    genSVG: function (res, isExp = false) {
        let type = res[0];
        let style = res[1];

        // 🚦 CAS 1 : FEUX TRICOLORES
        if (type.startsWith('light_')) {
            let status = type.split('_')[1]; // green, orange, red, off
            let w = isExp ? 120 : 60; let h = isExp ? 320 : 160;

            let cRed = status === 'red' ? '#ff4757' : '#2f3542';
            let cOrg = status === 'orange' ? '#ffa502' : '#2f3542';
            let cGrn = status === 'green' ? '#2ed573' : '#2f3542';

            let glowR = (status === 'red' && style === 'neon') ? `filter="drop-shadow(0px 0px 15px ${cRed})"` : '';
            let glowO = (status === 'orange' && style === 'neon') ? `filter="drop-shadow(0px 0px 15px ${cOrg})"` : '';
            let glowG = (status === 'green' && style === 'neon') ? `filter="drop-shadow(0px 0px 15px ${cGrn})"` : '';

            return `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 120 320" width="${isExp ? w : '100%'}" height="${isExp ? h : '100%'}">
                <rect x="10" y="10" width="100" height="300" rx="20" fill="#1e272e" stroke="#57606f" stroke-width="4"/>
                <circle cx="60" cy="65" r="35" fill="${cRed}" ${glowR}/>
                <circle cx="60" cy="160" r="35" fill="${cOrg}" ${glowO}/>
                <circle cx="60" cy="255" r="35" fill="${cGrn}" ${glowG}/>
            </svg>`;
        }

        // 🛑 CAS 2 : PANNEAUX DE SIGNALISATION
        else if (type.startsWith('sign_')) {
            let sign = type.split('_')[1]; // stop, warning, forbidden, yield, silence
            let size = isExp ? 200 : 100; // Les panneaux sont carrés

            let svg = `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 100 100" width="${size}" height="${size}">`;

            if (sign === 'stop') {
                svg += `<polygon points="30,5 70,5 95,30 95,70 70,95 30,95 5,70 5,30" fill="#e74c3c" stroke="#c0392b" stroke-width="2"/>`;
                svg += `<text x="50" y="60" font-family="sans-serif" font-weight="bold" font-size="26" fill="white" text-anchor="middle">STOP</text>`;
            }
            else if (sign === 'warning') {
                svg += `<polygon points="50,15 90,85 10,85" fill="#f1c40f" stroke="#e74c3c" stroke-width="8" stroke-linejoin="round"/>`;
                svg += `<text x="50" y="73" font-family="sans-serif" font-weight="bold" font-size="45" fill="#2c3e50" text-anchor="middle">!</text>`;
            }
            else if (sign === 'forbidden') {
                svg += `<circle cx="50" cy="50" r="42" fill="#e74c3c"/>`;
                svg += `<rect x="25" y="42" width="50" height="16" fill="white"/>`;
            }
            else if (sign === 'yield') {
                svg += `<polygon points="10,15 90,15 50,85" fill="white" stroke="#e74c3c" stroke-width="8" stroke-linejoin="round"/>`;
            }
            else if (sign === 'silence') {
                svg += `<circle cx="50" cy="50" r="40" fill="white" stroke="#e74c3c" stroke-width="8"/>`;
                svg += `<text x="50" y="62" font-family="sans-serif" font-weight="bold" font-size="34" fill="#2c3e50" text-anchor="middle">Chut</text>`;
                svg += `<path d="M25,25 L75,75" stroke="#e74c3c" stroke-width="8"/>`;
            }

            svg += `</svg>`;
            return svg;
        }
    },

    createImage: function (svg, callback) {
        let base64 = btoa(unescape(encodeURIComponent(svg)));
        const img = new Image();
        img.onload = () => callback({ img: img, src: img.src, w: img.width, h: img.height });
        img.src = "data:image/svg+xml;base64," + base64;
    },

    onPointerMove: function (rawPos) {
        if (typeof mode !== 'undefined' && mode === 'traffic' && this.currentStamp) {
            mouseLogicalPos = { x: rawPos.x, y: rawPos.y };
            if (typeof draw === 'function') draw();
            return false;
        }
        return false;
    },

    onDraw: function (ctx) {
        if (typeof mode !== 'undefined' && mode === 'traffic' && this.currentStamp && typeof mouseLogicalPos !== 'undefined' && mouseLogicalPos) {
            ctx.globalAlpha = 0.8;
            ctx.drawImage(this.currentStamp.img, mouseLogicalPos.x - this.currentStamp.w / 2, mouseLogicalPos.y - this.currentStamp.h / 2, this.currentStamp.w, this.currentStamp.h);
            ctx.globalAlpha = 1.0;
        }
    },

    onPointerDown: function (rawPos) {
        if (typeof mode !== 'undefined' && mode === 'traffic' && this.currentStamp) {

            // 🔧 LA CORRECTION EST ICI : On met l'image générée dans le cache de l'application !
            if (typeof imageCache !== 'undefined') {
                imageCache[this.currentStamp.src] = this.currentStamp.img;
            }

            images.push({
                id: typeof nextId !== 'undefined' ? nextId++ : Date.now(),
                x: rawPos.x - this.currentStamp.w / 2,
                y: rawPos.y - this.currentStamp.h / 2,
                w: this.currentStamp.w,
                h: this.currentStamp.h,
                cx: 0, cy: 0, cw: this.currentStamp.w, ch: this.currentStamp.h,
                src: this.currentStamp.src,
                z: typeof globalZ !== 'undefined' ? globalZ++ : 1000,
                pluginData: { id: 'trafficLightTool', args: this.currentArgs }
            });

            if (typeof saveState === 'function') saveState();
            if (typeof setMode === 'function') setMode('pointer');

            // On désactive le bouton
            document.querySelectorAll('#plugins-grid .btn').forEach(b => b.classList.remove('active'));

            this.currentStamp = null;
            if (typeof draw === 'function') draw();
            return true;
        }
        return false;
    }
});


// ==========================================
// PLUGIN : POPCORN 5.1 (Icônes explicites, Souris Globale)
// ==========================================
registerPlugin('popcornTool', 'Jeux', {
    widgetEl: null, canvas: null, ctx: null, animFrame: null,

    game: {
        state: 'title', // title, levelselect, settings, playing, paused, gameover, levelclear, win
        score: 0, lives: 3, level: 0,
        width: 600, height: 400,
        baseSpeed: 6
    },

    keys: { left: false, right: false },
    paddle: { x: 250, y: 370, width: 100, normalWidth: 100, height: 10, speed: 8 },
    balls: [],

    bricks: [], particles: [], powerups: [], enemies: [],
    effects: { enlarge: 0, shrink: 0, slow: 0, fast: 0 },

    levels: [
        ["0000000000", "0111111110", "0111111110", "0000000000"],
        ["1010101010", "0101010101", "1010101010", "0101010101"],
        ["0000110000", "0001221000", "0012112100", "0121111210"],
        ["2222222222", "1111111111", "1111111111", "0000000000"],
        ["1100000011", "0110000110", "0011001100", "0001111000"],
        ["1210000121", "2120000212", "1210000121", "0000000000"],
        ["0110000110", "1221001221", "0110000110", "0000110000", "0001221000"],
        ["2222002222", "1111001111", "2222002222", "1111001111"],
        ["0202020202", "2020202020", "0202020202", "2020202020"],
        ["1111111111", "1000000001", "1022222201", "1000000001", "1111111111"],
        ["0022222200", "0200000020", "2001111002", "2001221002"],
        ["1200110021", "1200110021", "1200110021", "1200110021"],
        ["0012002100", "0122222210", "1220220221", "1222222221", "0122112210"],
        ["1000000000", "1200000000", "1210000000", "1212000000", "1212100000"],
        ["0000012121", "0000001212", "0000000121", "0000000012", "0000000001"],
        ["2121212121", "1212121212", "2121212121", "1212121212"],
        ["0000220000", "0002112000", "0021221200", "0212002120", "2120000212"],
        ["2211221122", "1122112211", "2211221122", "1122112211"],
        ["2222222222", "2000000002", "2022222202", "2020000202", "2022222202"],
        ["2222222222", "2222222222", "2222222222", "2222222222", "2222222222"]
    ],

    brickColors: { 1: '#48dbfb', 2: '#ff9ff3' },

    init: function () {
        const grid = document.getElementById('plugins-grid'); if (!grid) return;
        const btn = document.createElement('button'); btn.className = 'btn'; btn.title = 'Popcorn';
        btn.innerHTML = `<svg viewBox="0 0 24 24" class="stroke-icon" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">
            <!-- Paddle -->
            <rect x="9" y="20" width="6" height="2" rx="1" />
            <!-- Ball -->
            <circle cx="12" cy="17" r="1.5" fill="currentColor" />
            <!-- Bricks -->
            <rect x="3" y="5" width="4" height="2" />
            <rect x="10" y="5" width="4" height="2" />
            <rect x="17" y="5" width="4" height="2" />
            <rect x="6" y="8" width="4" height="2" />
            <rect x="14" y="8" width="4" height="2" />
        </svg>`;
        grid.appendChild(btn);

        btn.addEventListener('click', (e) => {
            e.stopPropagation();
            document.querySelectorAll('#bar-tools .btn, #bar-plugins .btn').forEach(b => b.classList.remove('active'));
            btn.classList.add('active');
            if (typeof setMode === 'function') setMode('pointer');
            this.openWidget();
        });

        window.addEventListener('keydown', (e) => {
            if (this.game.state !== 'playing') return;
            if (e.key === 'ArrowLeft') this.keys.left = true;
            if (e.key === 'ArrowRight') this.keys.right = true;
        });
        window.addEventListener('keyup', (e) => {
            if (e.key === 'ArrowLeft') this.keys.left = false;
            if (e.key === 'ArrowRight') this.keys.right = false;
        });

        // Suivi de la souris GLOBALE (même en dehors du canvas)
        window.addEventListener('mousemove', (e) => {
            if (this.game.state === 'playing' && !this.keys.left && !this.keys.right && this.canvas) {
                const rect = this.canvas.getBoundingClientRect();
                this.paddle.x = (e.clientX - rect.left) - this.paddle.width / 2;
                // Le bridage dans l'écran est géré dans la fonction update()
            }
        });
    },

    loadLevel: function (index) {
        this.bricks = []; this.particles = []; this.powerups = []; this.enemies = [];
        this.effects = { enlarge: 0, shrink: 0, slow: 0, fast: 0 };
        this.paddle.width = this.paddle.normalWidth;

        if (index >= this.levels.length) { this.game.state = 'win'; return; }
        this.game.level = index;

        const map = this.levels[index];
        const rows = map.length; const cols = map[0].length;
        const padding = 4; const offsetTop = 60; const offsetLeft = 40;
        const bWidth = (this.game.width - (offsetLeft * 2) - (padding * (cols - 1))) / cols;
        const bHeight = 18;

        for (let r = 0; r < rows; r++) {
            for (let c = 0; c < cols; c++) {
                let type = parseInt(map[r][c]);
                if (type > 0) {
                    this.bricks.push({
                        x: offsetLeft + c * (bWidth + padding), y: offsetTop + r * (bHeight + padding),
                        w: bWidth, h: bHeight, hp: type, color: this.brickColors[type]
                    });
                }
            }
        }
        this.resetBalls();
        this.game.state = 'playing';
        this.updateUI();
    },

    resetBalls: function () {
        this.balls = [{
            x: this.paddle.x + this.paddle.width / 2,
            y: this.paddle.y - 12,
            dx: (this.game.baseSpeed * 0.7) * (Math.random() > 0.5 ? 1 : -1),
            dy: -this.game.baseSpeed,
            radius: 6
        }];
    },

    triggerMultiball: function () {
        let newBalls = [];
        for (let b of this.balls) {
            newBalls.push({ x: b.x, y: b.y, dx: -b.dx, dy: b.dy - 1, radius: b.radius });
            newBalls.push({ x: b.x, y: b.y, dx: b.dx * 1.5, dy: b.dy, radius: b.radius });
        }
        this.balls = this.balls.concat(newBalls);
    },

    openWidget: function () {
        if (this.widgetEl) {
            this.widgetEl.style.display = 'block';
            this.game.state = 'title'; this.updateUI(); this.startGameLoop();
            return;
        }

        this.widgetEl = document.createElement('div');
        this.widgetEl.style.cssText = "position:fixed; top:10vh; left:calc(50% - 300px); width:600px; background:#1e272e; border-radius:12px; box-shadow:0 20px 50px rgba(0,0,0,0.5); z-index:100000; overflow:hidden; font-family:'Segoe UI', sans-serif; border:2px solid #3c40c6;";

        this.widgetEl.innerHTML = `
            <div id="pop-drag-handle" style="background:#0a0e14; padding:10px 15px; display:flex; justify-content:space-between; align-items:center; cursor:grab; user-select:none; border-bottom:1px solid #3c40c6;">
                <div style="font-weight:900; font-size:16px; color:#00d2d3; text-transform:uppercase; letter-spacing:2px;">🕹️ Popcorn</div>
                <div style="display:flex; gap:10px;">
                    <button id="pop-btn-pause" style="background:none; border:none; color:#feca57; cursor:pointer; font-weight:bold; font-size:16px; display:none;">⏸️</button>
                    <button id="pop-btn-home" style="background:none; border:none; color:#1dd1a1; cursor:pointer; font-weight:bold; font-size:16px; display:none;">🏠</button>
                    <button id="pop-btn-close" style="background:none; border:none; color:#ff6b6b; cursor:pointer; font-weight:bold; font-size:16px;">✕</button>
                </div>
            </div>
            <div style="position:relative; width:600px; height:400px; background:#1e272e; cursor:none;">
                <canvas id="pop-canvas" width="600" height="400" style="display:block;"></canvas>
            </div>
        `;
        document.body.appendChild(this.widgetEl);

        this.canvas = this.widgetEl.querySelector('#pop-canvas');
        this.ctx = this.canvas.getContext('2d');

        let isDragging = false, startX, startY;
        const handle = this.widgetEl.querySelector('#pop-drag-handle');
        handle.onmousedown = (e) => { if (e.target.closest('button')) return; isDragging = true; startX = e.clientX - this.widgetEl.offsetLeft; startY = e.clientY - this.widgetEl.offsetTop; };
        window.addEventListener('mousemove', (e) => { if (isDragging) { this.widgetEl.style.left = (e.clientX - startX) + 'px'; this.widgetEl.style.top = (e.clientY - startY) + 'px'; } });
        window.addEventListener('mouseup', () => { isDragging = false; });

        this.widgetEl.querySelector('#pop-btn-close').onclick = () => { this.widgetEl.style.display = 'none'; cancelAnimationFrame(this.animFrame); };

        this.widgetEl.querySelector('#pop-btn-pause').onclick = () => {
            if (this.game.state === 'playing') this.game.state = 'paused';
            else if (this.game.state === 'paused') this.game.state = 'playing';
            this.updateUI();
        };

        this.widgetEl.querySelector('#pop-btn-home').onclick = () => {
            this.game.state = 'title'; this.updateUI();
        };

        this.canvas.addEventListener('mousedown', (e) => {
            const rect = this.canvas.getBoundingClientRect();
            const rx = e.clientX - rect.left; const ry = e.clientY - rect.top;

            if (this.game.state === 'title') {
                if (rx > 200 && rx < 400 && ry > 220 && ry < 270) { this.game.score = 0; this.game.lives = 3; this.loadLevel(0); }
                else if (rx > 200 && rx < 400 && ry > 280 && ry < 320) { this.game.state = 'levelselect'; this.updateUI(); }
                else if (rx > 200 && rx < 400 && ry > 330 && ry < 370) { this.game.state = 'settings'; this.updateUI(); }
            }
            else if (this.game.state === 'levelselect') {
                if (rx > 20 && rx < 80 && ry > 20 && ry < 50) { this.game.state = 'title'; this.updateUI(); return; }
                let col = Math.floor((rx - 50) / 100); let row = Math.floor((ry - 80) / 70);
                if (col >= 0 && col < 5 && row >= 0 && row < 4) {
                    let lvl = row * 5 + col;
                    if (lvl < this.levels.length) { this.game.score = 0; this.game.lives = 3; this.loadLevel(lvl); }
                }
            }
            else if (this.game.state === 'settings') {
                if (rx > 20 && rx < 80 && ry > 20 && ry < 50) { this.game.state = 'title'; this.updateUI(); return; }
                if (rx > 150 && rx < 230 && ry > 180 && ry < 220) this.game.baseSpeed = 4;
                if (rx > 250 && rx < 350 && ry > 180 && ry < 220) this.game.baseSpeed = 6;
                if (rx > 370 && rx < 450 && ry > 180 && ry < 220) this.game.baseSpeed = 9;
            }
            else if (this.game.state === 'gameover' || this.game.state === 'win') {
                this.game.state = 'title'; this.updateUI();
            }
            else if (this.game.state === 'levelclear') {
                this.loadLevel(this.game.level + 1);
            }
        });

        this.game.state = 'title';
        this.updateUI();
        this.startGameLoop();
    },

    updateUI: function () {
        const btnPause = this.widgetEl.querySelector('#pop-btn-pause');
        const btnHome = this.widgetEl.querySelector('#pop-btn-home');
        if (this.game.state === 'playing' || this.game.state === 'paused') {
            btnPause.style.display = 'block'; btnHome.style.display = 'block';
            btnPause.innerText = this.game.state === 'paused' ? '▶️' : '⏸️';
            this.canvas.style.cursor = 'none'; // Cache la souris en jeu
        } else {
            btnPause.style.display = 'none'; btnHome.style.display = 'none';
            this.canvas.style.cursor = 'crosshair';
        }
    },

    spawnPowerup: function (x, y) {
        if (Math.random() > 0.20) return;
        let isMalus = Math.random() > 0.80;
        let type = ''; let color = '';
        if (isMalus) {
            let pool = ['X', 'F'];
            type = pool[Math.floor(Math.random() * pool.length)];
            color = type === 'X' ? '#ff4757' : '#ff7f50';
        } else {
            let pool = ['E', 'S', 'V', 'M'];
            type = pool[Math.floor(Math.random() * pool.length)];
            const cMap = { 'E': '#00d2d3', 'S': '#1dd1a1', 'V': '#ff9ff3', 'M': '#feca57' };
            color = cMap[type];
        }
        this.powerups.push({ x: x, y: y, r: 12, type: type, color: color, isMalus: isMalus });
    },

    spawnEnemy: function () {
        this.enemies.push({
            x: Math.random() * (this.game.width - 40) + 20, y: 0,
            vx: (Math.random() - 0.5) * 4, vy: 1 + Math.random() * 1.5,
            angle: 0, vAngle: (Math.random() - 0.5) * 0.2, r: 14, color: '#ff4757'
        });
    },

    createExplosion: function (x, y, color) {
        for (let i = 0; i < 20; i++) {
            this.particles.push({
                x: x, y: y, vx: (Math.random() - 0.5) * 10, vy: (Math.random() - 0.5) * 10,
                life: 1.0, color: color
            });
        }
    },

    update: function () {
        if (this.game.state !== 'playing') return;

        // Clavier
        if (this.keys.left) this.paddle.x -= this.paddle.speed;
        if (this.keys.right) this.paddle.x += this.paddle.speed;

        // Bridage Raquette
        if (this.paddle.x < 0) this.paddle.x = 0;
        if (this.paddle.x + this.paddle.width > this.game.width) this.paddle.x = this.game.width - this.paddle.width;

        if (Math.random() < 0.003) this.spawnEnemy();

        // Effets Temporaires
        if (this.effects.enlarge > 0) { this.effects.enlarge--; this.paddle.width = 160; }
        else if (this.effects.shrink > 0) { this.effects.shrink--; this.paddle.width = 50; }
        else { this.paddle.width = this.paddle.normalWidth; }

        let currentSpeedMult = 1.0;
        if (this.effects.slow > 0) { this.effects.slow--; currentSpeedMult = 0.6; }
        if (this.effects.fast > 0) { this.effects.fast--; currentSpeedMult = 1.6; }

        // Balles
        for (let i = this.balls.length - 1; i >= 0; i--) {
            let ball = this.balls[i];
            let speed = Math.hypot(ball.dx, ball.dy);
            let targetSpeed = this.game.baseSpeed * currentSpeedMult;

            if (speed > 0) { ball.dx = (ball.dx / speed) * targetSpeed; ball.dy = (ball.dy / speed) * targetSpeed; }
            ball.x += ball.dx; ball.y += ball.dy;

            if (ball.x + ball.dx > this.game.width - ball.radius || ball.x + ball.dx < ball.radius) ball.dx = -ball.dx;
            if (ball.y + ball.dy < ball.radius) ball.dy = -ball.dy;
            else if (ball.y + ball.dy > this.game.height - ball.radius) {
                this.balls.splice(i, 1);
                continue;
            }

            if (ball.y + ball.radius >= this.paddle.y && ball.x >= this.paddle.x && ball.x <= this.paddle.x + this.paddle.width) {
                ball.dy = -Math.abs(ball.dy);
                let hitPoint = ball.x - (this.paddle.x + this.paddle.width / 2);
                ball.dx = hitPoint * 0.15;
                ball.y = this.paddle.y - ball.radius;
            }

            for (let j = this.bricks.length - 1; j >= 0; j--) {
                let b = this.bricks[j];
                let testX = ball.x; let testY = ball.y;

                if (ball.x < b.x) testX = b.x; else if (ball.x > b.x + b.w) testX = b.x + b.w;
                if (ball.y < b.y) testY = b.y; else if (ball.y > b.y + b.h) testY = b.y + b.h;

                if (Math.hypot(ball.x - testX, ball.y - testY) <= ball.radius) {
                    if (testX === b.x || testX === b.x + b.w) ball.dx = -ball.dx; else ball.dy = -ball.dy;
                    b.hp--; this.game.score += 10;

                    if (b.hp <= 0) {
                        this.createExplosion(b.x + b.w / 2, b.y + b.h / 2, b.color);
                        this.spawnPowerup(b.x + b.w / 2, b.y + b.h / 2);
                        this.bricks.splice(j, 1);
                    } else { b.color = this.brickColors[b.hp]; }
                }
            }
        }

        if (this.balls.length === 0) {
            this.game.lives--; this.effects = { enlarge: 0, shrink: 0, slow: 0, fast: 0 };
            if (this.game.lives <= 0) this.game.state = 'gameover'; else this.resetBalls();
        }
        if (this.bricks.length === 0) { this.game.state = 'levelclear'; this.updateUI(); }

        // Ennemis
        for (let i = this.enemies.length - 1; i >= 0; i--) {
            let e = this.enemies[i];
            e.x += e.vx; e.y += e.vy; e.angle += e.vAngle;
            if (e.x < e.r || e.x > this.game.width - e.r) e.vx *= -1;

            let hitBall = false;
            for (let b of this.balls) {
                if (Math.hypot(b.x - e.x, b.y - e.y) < b.radius + e.r) {
                    this.createExplosion(e.x, e.y, e.color);
                    this.game.score += 30; b.dy *= -1; hitBall = true; break;
                }
            }
            if (hitBall) { this.enemies.splice(i, 1); continue; }

            if (e.y + e.r > this.paddle.y && e.x > this.paddle.x && e.x < this.paddle.x + this.paddle.width) {
                this.createExplosion(e.x, e.y, e.color); this.enemies.splice(i, 1);
                this.paddle.width = Math.max(20, this.paddle.width - 20);
                continue;
            }
            if (e.y > this.game.height + e.r) this.enemies.splice(i, 1);
        }

        // Powerups
        for (let i = this.powerups.length - 1; i >= 0; i--) {
            let p = this.powerups[i];
            p.y += 2.5;
            if (p.y + p.r > this.paddle.y && p.x > this.paddle.x && p.x < this.paddle.x + this.paddle.width) {
                if (p.type === 'E') { this.effects.enlarge = 600; this.effects.shrink = 0; }
                if (p.type === 'X') { this.effects.shrink = 400; this.effects.enlarge = 0; }
                if (p.type === 'S') { this.effects.slow = 600; this.effects.fast = 0; }
                if (p.type === 'F') { this.effects.fast = 400; this.effects.slow = 0; }
                if (p.type === 'V') this.game.lives++;
                if (p.type === 'M') this.triggerMultiball();

                this.game.score += p.isMalus ? -50 : 50;
                this.powerups.splice(i, 1);
            } else if (p.y > this.game.height) { this.powerups.splice(i, 1); }
        }

        // Particules
        for (let i = this.particles.length - 1; i >= 0; i--) {
            let p = this.particles[i];
            p.x += p.vx; p.y += p.vy; p.life -= 0.03;
            if (p.life <= 0) this.particles.splice(i, 1);
        }
    },

    drawGrid: function () {
        this.ctx.strokeStyle = "rgba(255, 255, 255, 0.05)"; this.ctx.lineWidth = 1;
        for (let i = 0; i < 600; i += 40) { this.ctx.beginPath(); this.ctx.moveTo(i, 0); this.ctx.lineTo(i, 400); this.ctx.stroke(); }
        for (let i = 0; i < 400; i += 40) { this.ctx.beginPath(); this.ctx.moveTo(0, i); this.ctx.lineTo(600, i); this.ctx.stroke(); }
    },

    drawButton: function (x, y, w, h, text, color) {
        this.ctx.save();
        this.ctx.fillStyle = color; this.ctx.shadowBlur = 10; this.ctx.shadowColor = color;
        this.ctx.beginPath(); this.ctx.roundRect(x, y, w, h, 8); this.ctx.fill();
        this.ctx.fillStyle = '#1e272e'; this.ctx.font = 'bold 18px sans-serif'; this.ctx.textAlign = 'center'; this.ctx.textBaseline = 'middle';
        this.ctx.shadowBlur = 0; this.ctx.fillText(text, x + w / 2, y + h / 2);
        this.ctx.restore();
    },

    draw: function () {
        const ctx = this.ctx;
        ctx.clearRect(0, 0, this.game.width, this.game.height);
        this.drawGrid();

        if (this.game.state === 'title') {
            ctx.textAlign = 'center'; ctx.textBaseline = 'middle';
            ctx.shadowBlur = 20; ctx.shadowColor = '#00d2d3'; ctx.fillStyle = '#00d2d3'; ctx.font = 'bold 70px sans-serif';
            ctx.fillText("POPCORN", this.game.width / 2, 120);

            this.drawButton(200, 220, 200, 50, "JOUER", "#00d2d3");
            this.drawButton(200, 280, 200, 40, "NIVEAUX", "#feca57");
            this.drawButton(200, 330, 200, 40, "PARAMÈTRES", "#ff9ff3");
            return;
        }

        if (this.game.state === 'settings') {
            ctx.fillStyle = '#fff'; ctx.font = 'bold 30px sans-serif'; ctx.textAlign = 'center';
            ctx.fillText("VITESSE DE LA BALLE", this.game.width / 2, 120);

            this.drawButton(150, 180, 80, 40, "LENT", this.game.baseSpeed === 4 ? "#1dd1a1" : "#576574");
            this.drawButton(250, 180, 100, 40, "NORMAL", this.game.baseSpeed === 6 ? "#1dd1a1" : "#576574");
            this.drawButton(370, 180, 80, 40, "RAPIDE", this.game.baseSpeed === 9 ? "#1dd1a1" : "#576574");

            ctx.fillStyle = '#576574'; ctx.font = '16px sans-serif'; ctx.fillText("◀ Retour", 50, 35);
            return;
        }

        if (this.game.state === 'levelselect') {
            ctx.fillStyle = '#fff'; ctx.font = 'bold 30px sans-serif'; ctx.textAlign = 'center';
            ctx.fillText("CHOIX DU NIVEAU", this.game.width / 2, 40);
            ctx.fillStyle = '#576574'; ctx.font = '16px sans-serif'; ctx.fillText("◀ Retour", 50, 35);

            for (let i = 0; i < 20; i++) {
                let col = i % 5; let row = Math.floor(i / 5);
                let x = 50 + col * 100; let y = 80 + row * 70;
                ctx.fillStyle = '#2f3640'; ctx.beginPath(); ctx.roundRect(x, y, 80, 50, 6); ctx.fill();
                ctx.fillStyle = '#00d2d3'; ctx.font = 'bold 20px sans-serif'; ctx.textBaseline = 'middle';
                ctx.fillText(i + 1, x + 40, y + 25);
            }
            return;
        }

        // --- EN JEU ---
        for (let b of this.bricks) {
            ctx.save(); ctx.shadowBlur = 8; ctx.shadowColor = b.color; ctx.fillStyle = b.color;
            ctx.beginPath(); ctx.roundRect(b.x, b.y, b.w, b.h, 4); ctx.fill();
            if (b.hp === 1 && this.brickColors[2]) {
                ctx.strokeStyle = "rgba(0,0,0,0.3)"; ctx.lineWidth = 2;
                ctx.beginPath(); ctx.moveTo(b.x + 5, b.y + 5); ctx.lineTo(b.x + b.w - 5, b.y + b.h - 5); ctx.stroke();
            }
            ctx.restore();
        }

        // Dessin des Icônes Vectorielles (Bonus/Malus)
        for (let p of this.powerups) {
            ctx.save(); ctx.translate(p.x, p.y); ctx.shadowBlur = 10; ctx.shadowColor = p.color;

            // Halo noir + bordure colorée
            ctx.fillStyle = 'rgba(0,0,0,0.8)'; ctx.strokeStyle = p.color; ctx.lineWidth = 2;
            ctx.beginPath(); ctx.arc(0, 0, p.r, 0, Math.PI * 2); ctx.fill(); ctx.stroke();

            ctx.fillStyle = p.color; ctx.strokeStyle = p.color;

            // Icônes personnalisées
            if (p.type === 'V') { // Coeur
                ctx.scale(0.45, 0.45); ctx.translate(0, -3);
                ctx.beginPath(); ctx.moveTo(0, 3);
                ctx.bezierCurveTo(0, -5, -10, -5, -10, 0); ctx.bezierCurveTo(-10, 5, 0, 10, 0, 15);
                ctx.bezierCurveTo(0, 10, 10, 5, 10, 0); ctx.bezierCurveTo(10, -5, 0, -5, 0, 3);
                ctx.fill();
            } else if (p.type === 'E') { // Agrandir < >
                ctx.lineWidth = 2; ctx.beginPath();
                ctx.moveTo(-3, -3); ctx.lineTo(-6, 0); ctx.lineTo(-3, 3);
                ctx.moveTo(3, -3); ctx.lineTo(6, 0); ctx.lineTo(3, 3);
                ctx.moveTo(-6, 0); ctx.lineTo(6, 0); ctx.stroke();
            } else if (p.type === 'X') { // Rétrécir > <
                ctx.lineWidth = 2; ctx.beginPath();
                ctx.moveTo(-6, -3); ctx.lineTo(-3, 0); ctx.lineTo(-6, 3);
                ctx.moveTo(6, -3); ctx.lineTo(3, 0); ctx.lineTo(6, 3);
                ctx.moveTo(-3, 0); ctx.lineTo(3, 0); ctx.stroke();
            } else if (p.type === 'S') { // Sablier
                ctx.beginPath();
                ctx.moveTo(-4, -5); ctx.lineTo(4, -5); ctx.lineTo(-4, 5); ctx.lineTo(4, 5); ctx.closePath(); ctx.fill();
            } else if (p.type === 'F') { // Éclair
                ctx.beginPath();
                ctx.moveTo(1, -6); ctx.lineTo(-4, 1); ctx.lineTo(0, 1); ctx.lineTo(-1, 6); ctx.lineTo(4, -1); ctx.lineTo(0, -1); ctx.closePath();
                ctx.fill();
            } else if (p.type === 'M') { // Multiball (3 balles)
                ctx.beginPath(); ctx.arc(0, -3, 2.5, 0, Math.PI * 2); ctx.fill();
                ctx.beginPath(); ctx.arc(-4, 3, 2.5, 0, Math.PI * 2); ctx.fill();
                ctx.beginPath(); ctx.arc(4, 3, 2.5, 0, Math.PI * 2); ctx.fill();
            }
            ctx.restore();
        }

        // Ennemis
        for (let e of this.enemies) {
            ctx.save(); ctx.translate(e.x, e.y); ctx.rotate(e.angle);
            ctx.shadowBlur = 15; ctx.shadowColor = e.color; ctx.strokeStyle = e.color; ctx.lineWidth = 3;
            ctx.beginPath();
            for (let j = 0; j < 6; j++) { let a = j * Math.PI / 3; let r = (j % 2 === 0) ? e.r : e.r * 0.4; ctx.lineTo(Math.cos(a) * r, Math.sin(a) * r); }
            ctx.closePath(); ctx.stroke();
            ctx.fillStyle = '#fff'; ctx.beginPath(); ctx.arc(0, 0, 3, 0, Math.PI * 2); ctx.fill();
            ctx.restore();
        }

        // Raquette
        ctx.save(); ctx.shadowBlur = 10; ctx.shadowColor = '#00d2d3';
        ctx.fillStyle = '#00d2d3';
        if (this.effects.enlarge > 0) { ctx.fillStyle = '#00d2d3'; ctx.shadowColor = '#00d2d3'; }
        if (this.effects.shrink > 0) { ctx.fillStyle = '#ff4757'; ctx.shadowColor = '#ff4757'; }
        ctx.beginPath(); ctx.roundRect(this.paddle.x, this.paddle.y, this.paddle.width, this.paddle.height, 5); ctx.fill();
        ctx.restore();

        // Balles
        for (let b of this.balls) {
            ctx.save(); ctx.shadowBlur = 12; ctx.shadowColor = '#ffffff'; ctx.fillStyle = '#ffffff';
            if (this.effects.slow > 0) ctx.fillStyle = '#1dd1a1';
            if (this.effects.fast > 0) ctx.fillStyle = '#ff7f50';
            ctx.beginPath(); ctx.arc(b.x, b.y, b.radius, 0, Math.PI * 2); ctx.fill();
            ctx.restore();
        }

        // Particules
        for (let p of this.particles) {
            ctx.save(); ctx.globalAlpha = p.life; ctx.fillStyle = p.color; ctx.shadowBlur = 10; ctx.shadowColor = p.color;
            ctx.beginPath(); ctx.arc(p.x, p.y, 3, 0, Math.PI * 2); ctx.fill(); ctx.restore();
        }

        // UI Textes
        ctx.shadowBlur = 0; ctx.fillStyle = '#fff'; ctx.font = 'bold 16px sans-serif'; ctx.textBaseline = 'alphabetic';
        ctx.textAlign = 'left'; ctx.fillText(`SCORE: ${this.game.score}`, 15, 25); ctx.fillText(`NIVEAU: ${this.game.level + 1}`, 15, 45);
        ctx.textAlign = 'right'; ctx.fillText(`VIES: ${this.game.lives}`, this.game.width - 15, 25);

        if (this.game.state === 'paused') {
            ctx.fillStyle = 'rgba(0,0,0,0.5)'; ctx.fillRect(0, 0, this.game.width, this.game.height);
            ctx.textAlign = 'center'; ctx.textBaseline = 'middle';
            ctx.fillStyle = '#fff'; ctx.font = 'bold 40px sans-serif'; ctx.fillText("PAUSE", this.game.width / 2, this.game.height / 2);
        }
        else if (this.game.state === 'gameover' || this.game.state === 'levelclear' || this.game.state === 'win') {
            ctx.fillStyle = 'rgba(0,0,0,0.7)'; ctx.fillRect(0, 0, this.game.width, this.game.height);
            ctx.textAlign = 'center'; ctx.textBaseline = 'middle';

            if (this.game.state === 'gameover') {
                ctx.fillStyle = '#ff4757'; ctx.font = 'bold 40px sans-serif'; ctx.shadowBlur = 20; ctx.shadowColor = '#ff4757';
                ctx.fillText("GAME OVER", this.game.width / 2, this.game.height / 2);
            } else if (this.game.state === 'levelclear') {
                ctx.fillStyle = '#feca57'; ctx.font = 'bold 40px sans-serif'; ctx.shadowBlur = 20; ctx.shadowColor = '#feca57';
                ctx.fillText("NIVEAU TERMINÉ", this.game.width / 2, this.game.height / 2);
            } else if (this.game.state === 'win') {
                ctx.fillStyle = '#1dd1a1'; ctx.font = 'bold 40px sans-serif'; ctx.shadowBlur = 20; ctx.shadowColor = '#1dd1a1';
                ctx.fillText("VICTOIRE !", this.game.width / 2, this.game.height / 2);
            }
            ctx.shadowBlur = 0; ctx.fillStyle = '#fff'; ctx.font = '20px sans-serif';
            ctx.fillText("Cliquez pour continuer", this.game.width / 2, this.game.height / 2 + 40);
        }
    },

    startGameLoop: function () {
        cancelAnimationFrame(this.animFrame);
        const loop = () => { this.update(); this.draw(); this.animFrame = requestAnimationFrame(loop); };
        loop();
    }
});

// ==========================================
// 2. ARBRE STUDIO (Fractions Vraies + Bug Cache Corrigé)
// ==========================================
registerPlugin('probabilityTreeTool', 'Maths - Numérique', {
    currentStamp: null, currentTreeData: null,
    init: function () {
        const btn = document.createElement('button'); btn.className = 'btn'; btn.dataset.mode = 'probatree'; btn.title = 'Probabilité';
        btn.innerHTML = `<svg viewBox="0 0 24 24" class="stroke-icon" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">
    <path d="M4 12h4"/>
    <path d="M8 12l4-6h4"/>
    <path d="M8 12l4 6h4"/>
    <circle cx="4" cy="12" r="1.5" fill="currentColor" stroke="none"/>
    <circle cx="8" cy="12" r="1.5" fill="currentColor" stroke="none"/>
    <circle cx="12" cy="6" r="1.5" fill="currentColor" stroke="none"/>
    <circle cx="12" cy="18" r="1.5" fill="currentColor" stroke="none"/>
</svg>`;
        document.getElementById('plugins-grid').appendChild(btn);

        btn.addEventListener('click', (e) => {
            document.querySelectorAll('.btn').forEach(b => b.classList.remove('active')); btn.classList.add('active'); setMode('probatree');
            this.openStudio(null, (stamp, treeData) => {
                this.currentStamp = stamp; this.currentTreeData = treeData;
                showToast("Arbre généré ! (Échap pour annuler)"); draw();
            });
            e.stopPropagation();
        });
    },
    edit: function (imgObj) {
        this.openStudio(imgObj.pluginData.args, (stamp, treeData) => {
            // CORRECTION CACHE ICI AUSSI
            if (typeof imageCache !== 'undefined') imageCache[stamp.src] = stamp.img;

            imgObj.src = stamp.src; imgObj.w = stamp.w; imgObj.h = stamp.h;
            imgObj.cw = stamp.w; imgObj.ch = stamp.h; imgObj.pluginData.args = treeData;
            draw(); saveState();
        });
    },

    openStudio: function (initialData, onValidate) {
        const overlay = document.createElement('div');
        overlay.style.cssText = "position:fixed;top:0;left:0;width:100%;height:100%;background:rgba(0,0,0,0.7);z-index:99999;display:flex;justify-content:center;align-items:center;";

        const box = document.createElement('div');
        box.style.cssText = "width:90%;height:85%;background:#fff;border-radius:12px;display:flex;overflow:hidden;box-shadow:0 20px 40px rgba(0,0,0,0.4); font-family:sans-serif;";

        box.innerHTML = `
            <div style="width:300px; background:#f8f9fa; border-right:1px solid #dfe6e9; padding:20px; display:flex; flex-direction:column; gap:15px;">
                <h3 style="margin:0; color:#2d3436; font-size:18px;">🌳 Arbre Studio</h3>
                <div id="tree-sel-none" style="color:#636e72; font-size:13px; margin-top:20px; text-align:center; padding: 20px; border: 2px dashed #b2bec3; border-radius: 8px;">
                    Cliquez sur un nœud de l'arbre pour le modifier.
                </div>
                
                <div id="tree-sel-panel" style="display:none; flex-direction:column; gap:12px;">
                    <div>
                        <label style="font-size:12px; font-weight:bold; color:#636e72;">Nom de l'événement</label>
                        <div style="display:flex; gap:8px;">
                            <input type="text" id="tree-inp-name" style="flex:1; padding:8px; border:1px solid #b2bec3; border-radius:4px; font-size:14px;">
                            <button id="tree-btn-bar" style="padding:8px 12px; border:1px solid #b2bec3; background:#fff; border-radius:4px; cursor:pointer; font-weight:bold;" title="Événement contraire">A̅</button>
                        </div>
                    </div>
                    <div>
                        <label style="font-size:12px; font-weight:bold; color:#636e72;">Probabilité (ex: 1/3, p)</label>
                        <input type="text" id="tree-inp-prob" placeholder="Utilisez / pour une vraie fraction" style="width:100%; padding:8px; border:1px solid #b2bec3; border-radius:4px; box-sizing:border-box; font-size:14px;">
                    </div>
                    <div style="display:flex; gap:8px; margin-top:10px;">
                        <button id="tree-btn-add" style="flex:1; padding:10px; background:#00b894; color:white; border:none; border-radius:4px; cursor:pointer; font-weight:bold;">+ Enfant</button>
                        <button id="tree-btn-del" style="flex:1; padding:10px; background:#d63031; color:white; border:none; border-radius:4px; cursor:pointer; font-weight:bold;">Supprimer</button>
                    </div>
                </div>
                
                <div style="flex:1"></div>
                <button id="tree-btn-valid" style="padding:14px; background:#0984e3; color:white; border:none; border-radius:6px; font-size:16px; font-weight:bold; cursor:pointer; box-shadow: 0 4px 6px rgba(9, 132, 227, 0.3);">✅ Terminer l'Arbre</button>
                <button id="tree-btn-cancel" style="padding:10px; background:transparent; color:#636e72; border:1px solid #b2bec3; border-radius:6px; font-size:14px; cursor:pointer;">Annuler</button>
            </div>
            <div style="flex:1; background:#ffffff; position:relative; overflow:hidden;" id="tree-canvas-container">
                <svg id="tree-svg-workspace" width="100%" height="100%"><g id="tree-svg-group" transform="translate(50, 50)"></g></svg>
            </div>
        `;
        overlay.appendChild(box);
        document.body.appendChild(overlay);

        let tree = initialData ? JSON.parse(JSON.stringify(initialData)) : {
            id: 1, name: 'Départ', prob: '', bar: false, children: [
                { id: 2, name: 'S', prob: '1/4', bar: false, children: [] },
                { id: 3, name: 'S', prob: '3/4', bar: true, children: [] }
            ]
        };

        let nextNodeId = 100;
        function updateNextId(n) { if (n.id >= nextNodeId) nextNodeId = n.id + 1; n.children.forEach(updateNextId); }
        updateNextId(tree);

        let selectedId = null;

        const selNone = document.getElementById('tree-sel-none');
        const selPanel = document.getElementById('tree-sel-panel');
        const inpName = document.getElementById('tree-inp-name');
        const inpProb = document.getElementById('tree-inp-prob');
        const btnBar = document.getElementById('tree-btn-bar');
        const btnAdd = document.getElementById('tree-btn-add');
        const btnDel = document.getElementById('tree-btn-del');
        const svgGroup = document.getElementById('tree-svg-group');
        const svgWorkspace = document.getElementById('tree-svg-workspace');

        function findNode(n, id) { if (n.id === id) return n; for (let c of n.children) { let res = findNode(c, id); if (res) return res; } return null; }
        function deleteNode(n, id) { let idx = n.children.findIndex(c => c.id === id); if (idx > -1) { n.children.splice(idx, 1); return true; } for (let c of n.children) { if (deleteNode(c, id)) return true; } return false; }

        function updateUI() {
            if (!selectedId) { selNone.style.display = 'block'; selPanel.style.display = 'none'; return; }
            const node = findNode(tree, selectedId);
            if (!node) return;
            selNone.style.display = 'none'; selPanel.style.display = 'flex';
            inpName.value = node.name;
            inpProb.value = node.prob;
            btnBar.style.background = node.bar ? '#dfe6e9' : '#fff';
            btnDel.style.display = (node.id === 1) ? 'none' : 'block';
            inpName.disabled = (node.id === 1);
            inpProb.disabled = (node.id === 1);
            btnBar.disabled = (node.id === 1);
        }

        inpName.oninput = () => { let n = findNode(tree, selectedId); if (n) { n.name = inpName.value; render(); } };
        inpProb.oninput = () => { let n = findNode(tree, selectedId); if (n) { n.prob = inpProb.value; render(); } };
        btnBar.onclick = () => { let n = findNode(tree, selectedId); if (n) { n.bar = !n.bar; updateUI(); render(); } };
        btnAdd.onclick = () => { let n = findNode(tree, selectedId); if (n) { n.children.push({ id: nextNodeId++, name: 'A', prob: 'p', bar: false, children: [] }); render(); } };
        btnDel.onclick = () => { if (selectedId !== 1) { deleteNode(tree, selectedId); selectedId = null; updateUI(); render(); } };

        function layout(n, depth, counter) {
            if (!n.children || n.children.length === 0) {
                n.x = depth * 220; n.y = counter.val * 100; counter.val++;
            } else {
                n.children.forEach(c => layout(c, depth + 1, counter));
                n.x = depth * 220; n.y = (n.children[0].y + n.children[n.children.length - 1].y) / 2;
            }
        }

        function render() {
            let counter = { val: 0 };
            layout(tree, 0, counter);
            svgGroup.innerHTML = '';

            let minX = Infinity, maxX = -Infinity, minY = Infinity, maxY = -Infinity;
            function getBounds(n) { if (n.x < minX) minX = n.x; if (n.x > maxX) maxX = n.x; if (n.y < minY) minY = n.y; if (n.y > maxY) maxY = n.y; n.children.forEach(getBounds); }
            getBounds(tree);
            const wBox = svgWorkspace.clientWidth; const hBox = svgWorkspace.clientHeight;
            const offsetX = (wBox - (maxX - minX)) / 2 - minX;
            const offsetY = (hBox - (maxY - minY)) / 2 - minY;
            svgGroup.setAttribute('transform', `translate(${offsetX}, ${offsetY})`);

            function drawLinks(n) {
                n.children.forEach(c => {
                    const midX = (n.x + c.x) / 2; const midY = (n.y + c.y) / 2;
                    const path = document.createElementNS("http://www.w3.org/2000/svg", "path");
                    path.setAttribute('d', `M ${n.x} ${n.y} C ${midX} ${n.y}, ${midX} ${c.y}, ${c.x} ${c.y}`);
                    path.setAttribute('fill', 'none'); path.setAttribute('stroke', '#2d3436'); path.setAttribute('stroke-width', '3');
                    svgGroup.appendChild(path);

                    if (c.prob) {
                        const bg = document.createElementNS("http://www.w3.org/2000/svg", "rect");

                        // 🌟 LOGIQUE DES VRAIES FRACTIONS 🌟
                        if (c.prob.includes('/')) {
                            const parts = c.prob.split('/');
                            const num = parts[0]; const den = parts[1];
                            const w = Math.max(num.length, den.length) * 10 + 16;
                            const h = 40;

                            bg.setAttribute('x', midX - w / 2); bg.setAttribute('y', midY - h / 2);
                            bg.setAttribute('width', w); bg.setAttribute('height', h);
                            bg.setAttribute('fill', '#ffffff'); bg.setAttribute('rx', '6');
                            svgGroup.appendChild(bg);

                            // Numérateur
                            const tNum = document.createElementNS("http://www.w3.org/2000/svg", "text");
                            tNum.setAttribute('x', midX); tNum.setAttribute('y', midY - 8);
                            tNum.setAttribute('text-anchor', 'middle'); tNum.setAttribute('font-family', 'sans-serif'); tNum.setAttribute('font-size', '14px'); tNum.setAttribute('fill', '#0984e3');
                            tNum.textContent = num;
                            svgGroup.appendChild(tNum);

                            // Trait de fraction
                            const bar = document.createElementNS("http://www.w3.org/2000/svg", "line");
                            bar.setAttribute('x1', midX - w / 2 + 6); bar.setAttribute('y1', midY);
                            bar.setAttribute('x2', midX + w / 2 - 6); bar.setAttribute('y2', midY);
                            bar.setAttribute('stroke', '#0984e3'); bar.setAttribute('stroke-width', '2');
                            svgGroup.appendChild(bar);

                            // Dénominateur
                            const tDen = document.createElementNS("http://www.w3.org/2000/svg", "text");
                            tDen.setAttribute('x', midX); tDen.setAttribute('y', midY + 14);
                            tDen.setAttribute('text-anchor', 'middle'); tDen.setAttribute('font-family', 'sans-serif'); tDen.setAttribute('font-size', '14px'); tDen.setAttribute('fill', '#0984e3');
                            tDen.textContent = den;
                            svgGroup.appendChild(tDen);

                        } else {
                            // Affichage normal si ce n'est pas une fraction
                            const w = c.prob.length * 10 + 16;
                            bg.setAttribute('x', midX - w / 2); bg.setAttribute('y', midY - 14);
                            bg.setAttribute('width', w); bg.setAttribute('height', 28);
                            bg.setAttribute('fill', '#ffffff'); bg.setAttribute('rx', '6');
                            svgGroup.appendChild(bg);

                            const txt = document.createElementNS("http://www.w3.org/2000/svg", "text");
                            txt.setAttribute('x', midX); txt.setAttribute('y', midY);
                            txt.setAttribute('text-anchor', 'middle'); txt.setAttribute('dominant-baseline', 'central');
                            txt.setAttribute('font-family', 'sans-serif'); txt.setAttribute('font-size', '16px'); txt.setAttribute('fill', '#0984e3');
                            txt.textContent = c.prob;
                            svgGroup.appendChild(txt);
                        }
                    }
                    drawLinks(c);
                });
            }
            function drawNodes(n) {
                const g = document.createElementNS("http://www.w3.org/2000/svg", "g");
                g.style.cursor = 'pointer';
                g.onclick = (e) => { e.stopPropagation(); selectedId = n.id; updateUI(); render(); };

                if (selectedId === n.id) {
                    const halo = document.createElementNS("http://www.w3.org/2000/svg", "circle");
                    halo.setAttribute('cx', n.x); halo.setAttribute('cy', n.y); halo.setAttribute('r', '24');
                    halo.setAttribute('fill', 'none'); halo.setAttribute('stroke', '#0984e3'); halo.setAttribute('stroke-width', '2'); halo.setAttribute('stroke-dasharray', '4,2');
                    g.appendChild(halo);
                }

                const c = document.createElementNS("http://www.w3.org/2000/svg", "circle");
                c.setAttribute('cx', n.x); c.setAttribute('cy', n.y); c.setAttribute('r', n.id === 1 ? '6' : '18');
                c.setAttribute('fill', n.id === 1 ? '#2d3436' : '#ffffff');
                if (n.id !== 1) { c.setAttribute('stroke', '#2d3436'); c.setAttribute('stroke-width', '3'); }
                g.appendChild(c);

                if (n.id !== 1) {
                    const t = document.createElementNS("http://www.w3.org/2000/svg", "text");
                    t.setAttribute('x', n.x); t.setAttribute('y', n.y);
                    t.setAttribute('text-anchor', 'middle'); t.setAttribute('dominant-baseline', 'central');
                    t.setAttribute('font-family', 'sans-serif'); t.setAttribute('font-size', '18px'); t.setAttribute('font-weight', 'bold'); t.setAttribute('fill', '#2d3436');
                    if (n.bar) t.setAttribute('text-decoration', 'overline');
                    t.textContent = n.name;
                    g.appendChild(t);
                }
                svgGroup.appendChild(g);
                n.children.forEach(drawNodes);
            }
            drawLinks(tree); drawNodes(tree);
        }

        svgWorkspace.onclick = () => { selectedId = null; updateUI(); render(); };

        document.getElementById('tree-btn-cancel').onclick = () => document.body.removeChild(overlay);
        document.getElementById('tree-btn-valid').onclick = () => {
            selectedId = null; render();

            let minX = Infinity, maxX = -Infinity, minY = Infinity, maxY = -Infinity;
            function getBounds(n) { if (n.x < minX) minX = n.x; if (n.x > maxX) maxX = n.x; if (n.y < minY) minY = n.y; if (n.y > maxY) maxY = n.y; n.children.forEach(getBounds); }
            getBounds(tree);

            const padding = 40;
            const finalW = maxX - minX + padding * 2;
            const finalH = maxY - minY + padding * 2;

            let exportSvg = `<svg xmlns="http://www.w3.org/2000/svg" viewBox="${minX - padding} ${minY - padding} ${finalW} ${finalH}" width="${finalW}" height="${finalH}">`;
            exportSvg += svgGroup.innerHTML;
            exportSvg += `</svg>`;

            document.body.removeChild(overlay);

            let base64 = btoa(unescape(encodeURIComponent(exportSvg)));
            const img = new Image();
            img.onload = () => onValidate({ img: img, src: img.src, w: finalW, h: finalH }, tree);
            img.src = "data:image/svg+xml;base64," + base64;
        };

        updateUI();
        setTimeout(render, 50);
    },

    onPointerMove: function (rawPos) {
        if (mode === 'probatree' && this.currentStamp) { mouseLogicalPos = { x: rawPos.x, y: rawPos.y }; if (typeof draw === 'function') draw(); return false; } return false;
    },
    onDraw: function (ctx) {
        if (mode === 'probatree' && this.currentStamp && typeof mouseLogicalPos !== 'undefined' && mouseLogicalPos) {
            ctx.globalAlpha = 0.8;
            ctx.drawImage(this.currentStamp.img, mouseLogicalPos.x - this.currentStamp.w / 2, mouseLogicalPos.y - this.currentStamp.h / 2, this.currentStamp.w, this.currentStamp.h);
            ctx.globalAlpha = 1.0;
        }
    },
    onPointerDown: function (rawPos) {
        if (mode === 'probatree' && this.currentStamp) {
            // 🌟 LE FIX DU BUG EST ICI 🌟 : On donne l'image en direct au système de cache du script principal
            if (typeof imageCache !== 'undefined') {
                imageCache[this.currentStamp.src] = this.currentStamp.img;
            }

            images.push({ id: nextId++, x: rawPos.x - this.currentStamp.w / 2, y: rawPos.y - this.currentStamp.h / 2, w: this.currentStamp.w, h: this.currentStamp.h, cx: 0, cy: 0, cw: this.currentStamp.w, ch: this.currentStamp.h, src: this.currentStamp.src, z: globalZ++, pluginData: { id: 'probabilityTreeTool', args: this.currentTreeData } });
            saveState(); setMode('pointer'); this.currentStamp = null; draw(); return true;
        }
        return false;
    }
});



// ==========================================
// GÉNÉRATEUR D'EXERCICES GLOBAL (V3)
// ==========================================
registerPlugin('globalExerciseGenerator', 'Exercices', {
    widgetEl: null,

    init: function () {
        const grid = document.getElementById('plugins-grid');
        if (!grid) return;
        const btn = document.createElement('button'); btn.className = 'btn'; btn.title = 'Générateur d\'Exercices';
        btn.innerHTML = `<svg viewBox="0 0 24 24" class="stroke-icon" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M4 19.5A2.5 2.5 0 0 1 6.5 17H20"></path><path d="M6.5 2H20v20H6.5A2.5 2.5 0 0 1 4 19.5v-15A2.5 2.5 0 0 1 6.5 2z"></path></svg>`;
        btn.addEventListener('click', (e) => {
            e.stopPropagation();
            if (this.widgetEl && this.widgetEl.style.display !== 'none') { this.widgetEl.style.display = 'none'; return; }
            this.openWidget();
        });
        grid.appendChild(btn);
    },

    openWidget: function (existingState = null) {
        if (!this.widgetEl) {
            this.widgetEl = document.createElement('div');
            this.widgetEl.style.cssText = `position:fixed; top:80px; left:120px; width:750px; background:#fff; border-radius:12px; box-shadow:0 15px 40px rgba(0,0,0,0.2); z-index:10000; font-family:sans-serif; border:1px solid #dfe6e9; overflow:hidden; display:flex; flex-direction:column;`;

            this.widgetEl.innerHTML = `
                <div class="geg-header" style="background:#1e272e; color:#fff; padding:12px 15px; display:flex; justify-content:space-between; align-items:center; cursor:grab; font-weight:bold;">
                    <div>📝 Générateur d'exercices</div>
                    <button id="geg-close" style="background:none; border:none; color:#ff7675; cursor:pointer; font-size:16px;">✕</button>
                </div>
                <div style="display:flex; flex:1;">
                    <!-- LEFT COLUMN : Themes -->
                    <div style="width:200px; border-right:1px solid #dfe6e9; background:#f8f9fa; display:flex; flex-direction:column;">
                        <div style="padding:10px; font-size:12px; font-weight:bold; color:#636e72; text-transform:uppercase;">Thèmes</div>
                        <div id="geg-themes" style="display:flex; flex-direction:column;">
                            <div class="geg-theme-btn active" data-theme="math" style="padding:12px 15px; cursor:pointer; border-left:4px solid #0984e3; background:#fff; font-weight:bold; color:#2d3436;">Mathématiques</div>
                            <div class="geg-theme-btn" data-theme="relatifs" style="padding:12px 15px; cursor:pointer; border-left:4px solid transparent; font-weight:bold; color:#636e72;">Nombres Relatifs</div>
                            <div class="geg-theme-btn" data-theme="equation" style="padding:12px 15px; cursor:pointer; border-left:4px solid transparent; font-weight:bold; color:#636e72;">Équations</div>
                            <div class="geg-theme-btn" data-theme="conv" style="padding:12px 15px; cursor:pointer; border-left:4px solid transparent; font-weight:bold; color:#636e72;">Conversions</div>
                            <div class="geg-theme-btn" data-theme="conj" style="padding:12px 15px; cursor:pointer; border-left:4px solid transparent; font-weight:bold; color:#636e72;">Conjugaison</div>
                        </div>
                    </div>
                    
                    <!-- RIGHT COLUMN : Options & Preview -->
                    <div style="flex:1; display:flex; flex-direction:column; padding:15px; gap:12px; background:#fff;">
                        <div style="font-weight:bold; font-size:14px; color:#2d3436;">Types d'exercices (Mixables)</div>
                        <div id="geg-options" style="display:flex; flex-wrap:wrap; gap:10px;">
                            <!-- Dynamically populated based on theme -->
                        </div>
                        
                        <!-- Groups for conjugation -->
                        <div id="geg-group-wrap" style="display:none; flex-direction:column; gap:4px; margin-top:5px;">
                            <label style="font-weight:bold; font-size:12px; color:#2d3436;">Groupe Verbal</label>
                            <select id="geg-opt-group" style="padding:6px; border:1px solid #dfe6e9; border-radius:6px; outline:none; font-size:13px; width:200px;">
                                <option value="all">Mélangés (Tous les groupes)</option>
                                <option value="g1">1er Groupe (-er)</option>
                                <option value="g2">2ème Groupe (-ir)</option>
                                <option value="g3">3ème Groupe (irréguliers)</option>
                            </select>
                        </div>
                        
                        <div style="display:flex; gap:10px; margin-top:5px;">
                            <div style="flex:1; display:flex; flex-direction:column; gap:4px;">
                                <label style="font-weight:bold; font-size:12px; color:#2d3436;">Quantité</label>
                                <select id="geg-count" style="padding:6px; border:1px solid #dfe6e9; border-radius:6px; outline:none; font-size:13px;">
                                    <option value="10">10 questions</option>
                                    <option value="15">15 questions</option>
                                    <option value="20" selected>20 questions</option>
                                    <option value="30">30 questions</option>
                                    <option value="40">40 questions</option>
                                </select>
                            </div>
                            <div style="flex:1; display:flex; flex-direction:column; gap:4px;">
                                <label style="font-weight:bold; font-size:12px; color:#2d3436;">Colonnes</label>
                                <select id="geg-cols" style="padding:6px; border:1px solid #dfe6e9; border-radius:6px; outline:none; font-size:13px;">
                                    <option value="auto">Auto</option>
                                    <option value="1">1</option>
                                    <option value="2">2</option>
                                    <option value="3">3</option>
                                    <option value="4">4</option>
                                </select>
                            </div>
                            <div style="flex:1; display:flex; flex-direction:column; gap:4px;">
                                <label style="font-weight:bold; font-size:12px; color:#2d3436;">Minuteur</label>
                                <select id="geg-timer" style="padding:6px; border:1px solid #dfe6e9; border-radius:6px; outline:none; font-size:13px;">
                                    <option value="0">Libre</option>
                                    <option value="1">1 minute</option>
                                    <option value="3">3 minutes</option>
                                    <option value="5">5 minutes</option>
                                </select>
                            </div>
                        </div>
                        
                        <div id="geg-answers-wrap" style="display:none; background:#f1f2f6; padding:8px; border-radius:6px; align-items:center; gap:8px;">
                            <input type="checkbox" id="geg-show-ans" style="width:14px; height:14px; cursor:pointer;">
                            <label for="geg-show-ans" style="font-weight:bold; font-size:12px; color:#e15f41; cursor:pointer;">Afficher les réponses sur le tableau</label>
                        </div>
                        
                        <button id="geg-generate" style="background:#0984e3; color:#fff; border:none; padding:10px; border-radius:6px; font-weight:bold; font-size:14px; cursor:pointer; transition:0.2s;">Générer et Tamponner</button>
                    </div>
                </div>
                
                <!-- PREVIEW BOX -->
                <div style="border-top:1px solid #dfe6e9; background:#f5f6fa; padding:10px; display:flex; flex-direction:column; align-items:center;">
                    <div style="font-weight:bold; font-size:11px; color:#636e72; margin-bottom:5px;">Aperçu Complet</div>
                    <div id="geg-preview" style="width:100%; height:250px; overflow:hidden; border:1px solid #bdc3c7; border-radius:6px; background:#fff; box-shadow:0 4px 10px rgba(0,0,0,0.05); display:flex; justify-content:center; align-items:center;"></div>
                </div>
            `;
            document.body.appendChild(this.widgetEl);

            let isDragging = false, startX, startY;
            const header = this.widgetEl.querySelector('.geg-header');
            header.onmousedown = (e) => {
                if (e.target.closest('button')) return;
                isDragging = true; startX = e.clientX - this.widgetEl.offsetLeft; startY = e.clientY - this.widgetEl.offsetTop;
            };
            window.addEventListener('mousemove', (e) => { if (isDragging) { this.widgetEl.style.left = (e.clientX - startX) + 'px'; this.widgetEl.style.top = (e.clientY - startY) + 'px'; } });
            window.addEventListener('mouseup', () => { isDragging = false; });

            this.widgetEl.querySelector('#geg-close').onclick = () => this.widgetEl.style.display = 'none';
            this.widgetEl.querySelector('#geg-generate').onclick = () => this.generateAndStamp();

            const themes = this.widgetEl.querySelectorAll('.geg-theme-btn');
            themes.forEach(t => {
                t.onclick = () => {

                    themes.forEach(th => { th.classList.remove('active'); th.style.background = 'transparent'; th.style.borderLeftColor = 'transparent'; th.style.color = '#636e72'; });
                    t.classList.add('active'); t.style.background = '#fff'; t.style.borderLeftColor = '#0984e3'; t.style.color = '#2d3436';
                    this.currentTheme = t.dataset.theme;
                    this.renderOptions();
                    this.updatePreview();
                };
            });

            this.widgetEl.addEventListener('change', (e) => {
                if (e.target.id !== 'geg-show-ans') {
                    this.currentState = null; // force regen
                }
                this.updatePreview();
            });
        }

        this.widgetEl.style.display = 'flex';
        this.currentState = existingState || null;

        let ansWrap = this.widgetEl.querySelector('#geg-answers-wrap');
        let btnGen = this.widgetEl.querySelector('#geg-generate');
        let selCount = this.widgetEl.querySelector('#geg-count');
        let selTimer = this.widgetEl.querySelector('#geg-timer');
        let selCols = this.widgetEl.querySelector('#geg-cols');
        let chkAns = this.widgetEl.querySelector('#geg-show-ans');

        if (existingState) {
            ansWrap.style.display = 'flex';
            btnGen.innerText = "Mettre à jour le tableau";

            this.currentTheme = existingState.theme;
            const themes = this.widgetEl.querySelectorAll('.geg-theme-btn');
            themes.forEach(t => {
                t.style.background = 'transparent'; t.style.borderLeftColor = 'transparent'; t.style.color = '#636e72';
                if (t.dataset.theme === this.currentTheme) { t.style.background = '#fff'; t.style.borderLeftColor = '#0984e3'; t.style.color = '#2d3436'; }
            });

            this.renderOptions(existingState);
            selCount.value = existingState.count;
            selTimer.value = existingState.timer;
            if (selCols) selCols.value = existingState.forceCols || 'auto';
            chkAns.checked = existingState.showAnswers;

            selCount.disabled = true;
            this.disableOptions();
        } else {
            ansWrap.style.display = 'none';
            btnGen.innerText = "Générer et Tamponner";

            this.currentTheme = 'math';
            const themes = this.widgetEl.querySelectorAll('.geg-theme-btn');
            themes.forEach(t => {
                t.style.background = 'transparent'; t.style.borderLeftColor = 'transparent'; t.style.color = '#636e72';
                if (t.dataset.theme === 'math') { t.style.background = '#fff'; t.style.borderLeftColor = '#0984e3'; t.style.color = '#2d3436'; }
            });

            this.renderOptions();
            selCount.disabled = false;
            if (selCols) selCols.value = 'auto';
            chkAns.checked = false;

            this.editingImgObj = null;
        }

        this.updatePreview();
    },

    renderOptions: function (state = null) {
        let opts = this.widgetEl.querySelector('#geg-options');
        let groupWrap = this.widgetEl.querySelector('#geg-group-wrap');
        opts.innerHTML = '';
        groupWrap.style.display = 'none';

        const createCheckboxes = (options, selectedVals) => {
            let html = '';
            options.forEach((o, i) => {
                let isChecked = selectedVals ? selectedVals.includes(o.v) : (i === 0);
                html += `
                <label style="display:flex; align-items:center; gap:5px; background:#f1f2f6; padding:6px 10px; border-radius:20px; font-size:12px; cursor:pointer; user-select:none;">
                    <input type="checkbox" class="geg-opt-check" value="${o.v}" ${isChecked ? 'checked' : ''} style="cursor:pointer;">
                    ${o.l}
                </label>`;
            });
            return html;
        };

        let typesToRender = [];
        let checked = state ? state.types : null;

        if (this.currentTheme === 'math') {
            typesToRender = [
                { v: 'math_add', l: 'Additions' }, { v: 'math_sub', l: 'Soustractions' }, { v: 'math_mult', l: 'Multiplications' }, { v: 'math_div', l: 'Divisions' }
            ];
        }
        else if (this.currentTheme === 'relatifs') {
            typesToRender = [
                { v: 'relatifs_add', l: 'Additions' }, { v: 'relatifs_sub', l: 'Soustractions' }, { v: 'relatifs_mult', l: 'Multiplications' }
            ];
        }
        else if (this.currentTheme === 'equation') {
            typesToRender = [
                { v: 'equation_easy', l: 'Facile (x+a=b)' }, { v: 'equation_med', l: 'Moyen (ax=b)' }, { v: 'equation_hard', l: 'Avancé (ax+b=c)' }
            ];
        }
        else if (this.currentTheme === 'conv') {
            typesToRender = [
                { v: 'conv_len', l: 'Longueurs (km,m,cm)' }, { v: 'conv_mass', l: 'Masses (kg,g,mg)' }, { v: 'conv_cap', l: 'Capacités (L,cL)' }
            ];
        }
        else if (this.currentTheme === 'conj') {
            typesToRender = [
                { v: 'conj_present', l: 'Présent' }, { v: 'conj_imparfait', l: 'Imparfait' }, { v: 'conj_futur', l: 'Futur' }, { v: 'conj_pcompose', l: 'Passé Composé' }
            ];
            groupWrap.style.display = 'flex';
            if (state && state.group) this.widgetEl.querySelector('#geg-opt-group').value = state.group;
        }

        opts.innerHTML = createCheckboxes(typesToRender, checked);

        // Ensure at least one is checked
        let checkboxes = this.widgetEl.querySelectorAll('.geg-opt-check');
        checkboxes.forEach(chk => {
            chk.addEventListener('change', () => {
                let anyChecked = Array.from(checkboxes).some(c => c.checked);
                if (!anyChecked) chk.checked = true; // Prevent unchecking all
                this.currentState = null;
                this.updatePreview();
            });
        });
    },

    disableOptions: function () {
        let checks = this.widgetEl.querySelectorAll('.geg-opt-check');
        checks.forEach(c => c.disabled = true);
        let group = this.widgetEl.querySelector('#geg-opt-group');
        if (group) group.disabled = true;
    },

    getCheckedTypes: function () {
        let checks = this.widgetEl.querySelectorAll('.geg-opt-check');
        let vals = [];
        checks.forEach(c => { if (c.checked) vals.push(c.value); });
        return vals;
    },

    generateQuestions: function (theme, types, group, count) {
        let qs = [];

        for (let i = 0; i < count; i++) {
            let q = "", a = "";
            let type = types[Math.floor(Math.random() * types.length)];

            if (theme === 'math') {
                if (type === 'math_mult') { let n1 = Math.floor(Math.random() * 8) + 2, n2 = Math.floor(Math.random() * 8) + 2; q = `${n1} × ${n2} =`; a = `${n1 * n2}`; }
                else if (type === 'math_add') { let n1 = Math.floor(Math.random() * 89) + 11, n2 = Math.floor(Math.random() * 89) + 11; q = `${n1} + ${n2} =`; a = `${n1 + n2}`; }
                else if (type === 'math_sub') { let n1 = Math.floor(Math.random() * 89) + 11, n2 = Math.floor(Math.random() * (n1 - 5)) + 2; q = `${n1} - ${n2} =`; a = `${n1 - n2}`; }
                else if (type === 'math_div') { let n2 = Math.floor(Math.random() * 8) + 2, n1 = n2 * (Math.floor(Math.random() * 9) + 2); q = `${n1} ÷ ${n2} =`; a = `${n1 / n2}`; }
            }

            else if (theme === 'relatifs') {
                const getRel = () => { let n = Math.floor(Math.random() * 20) - 10; return n === 0 ? 1 : n; };
                const formatNum = (n) => n < 0 ? `(${n})` : `${n}`;

                let n1 = getRel(), n2 = getRel();
                if (type === 'relatifs_add') { q = `${formatNum(n1)} + ${formatNum(n2)} =`; a = `${n1 + n2}`; }
                else if (type === 'relatifs_sub') { q = `${formatNum(n1)} - ${formatNum(n2)} =`; a = `${n1 - n2}`; }
                else if (type === 'relatifs_mult') {
                    n1 = Math.floor(Math.random() * 19) - 9; if (n1 === 0) n1 = 2;
                    n2 = Math.floor(Math.random() * 19) - 9; if (n2 === 0) n2 = -3;
                    q = `${formatNum(n1)} × ${formatNum(n2)} =`; a = `${n1 * n2}`;
                }
            }

            else if (theme === 'equation') {
                if (type === 'equation_easy') { let n = Math.floor(Math.random() * 20) + 1, x = Math.floor(Math.random() * 20) + 1; q = `x + ${n} = ${x + n}  ➔  x =`; a = `${x}`; }
                else if (type === 'equation_med') { let n = Math.floor(Math.random() * 9) + 2, x = Math.floor(Math.random() * 11) + 2; q = `${n}x = ${n * x}  ➔  x =`; a = `${x}`; }
                else if (type === 'equation_hard') { let n = Math.floor(Math.random() * 4) + 2, x = Math.floor(Math.random() * 10) + 1, b = Math.floor(Math.random() * 10) + 1; q = `${n}x + ${b} = ${(n * x) + b}  ➔  x =`; a = `${x}`; }
            }

            else if (theme === 'conv') {
                const units = { 'conv_len': ['mm', 'cm', 'dm', 'm', 'dam', 'hm', 'km'], 'conv_mass': ['mg', 'cg', 'dg', 'g', 'dag', 'hg', 'kg'], 'conv_cap': ['mL', 'cL', 'dL', 'L', 'daL', 'hL'] };
                let list = units[type];
                let idx1 = Math.floor(Math.random() * list.length); let idx2 = Math.floor(Math.random() * list.length);
                while (idx1 === idx2) idx2 = Math.floor(Math.random() * list.length);
                let val = Math.floor(Math.random() * 999) + 1; if (Math.random() > 0.7) val = val / 10;

                let factor = Math.pow(10, idx1 - idx2);
                let ans = val * factor;
                ans = Math.round(ans * 100000) / 100000;

                q = `${val} ${list[idx1]} =`; a = `${ans} ${list[idx2]}`;
            }

            else if (theme === 'conj') {
                const v1 = ["Manger", "Chanter", "Jouer", "Danser", "Parler", "Aimer", "Gagner", "Trouver", "Donner", "Passer", "Laver", "Porter"];
                const v2 = ["Finir", "Choisir", "Grandir", "Rougir", "Agir", "Réfléchir", "Obéir", "Réussir", "Remplir", "Punir", "Fournir", "Bâtir"];
                const v3 = ["Prendre", "Aller", "Faire", "Dire", "Pouvoir", "Vouloir", "Venir", "Voir", "Partir", "Écrire", "Sortir", "Savoir"];

                let verbs = [];
                if (group === 'g1') verbs = v1;
                else if (group === 'g2') verbs = v2;
                else if (group === 'g3') verbs = v3;
                else verbs = [...v1, ...v2, ...v3];

                const pronouns = ["Je / J'", "Tu", "Il / Elle", "Nous", "Vous", "Ils / Elles"];
                const tenses = { 'conj_present': 'Présent', 'conj_imparfait': 'Imparfait', 'conj_futur': 'Futur', 'conj_pcompose': 'Passé Comp.' };

                let v = verbs[Math.floor(Math.random() * verbs.length)];
                let p = pronouns[Math.floor(Math.random() * pronouns.length)];
                let t = tenses[type];
                q = `${v} (${t}) ➔ ${p}`; a = ``; // La réponse en conjugaison demanderait un moteur, on laisse vide pour l'instant ou on pourrait mettre la vraie rep si on intègre un dico
            }

            qs.push({ q, a });
        }
        return qs;
    },

    updatePreview: function () {
        if (!this.widgetEl) return;
        let count = parseInt(this.widgetEl.querySelector('#geg-count').value);
        let showAnswers = this.widgetEl.querySelector('#geg-show-ans').checked;
        let groupEl = this.widgetEl.querySelector('#geg-opt-group');
        let group = groupEl ? groupEl.value : 'all';
        let colsVal = this.widgetEl.querySelector('#geg-cols').value;

        let types = this.getCheckedTypes();
        if (types.length === 0) return; // Wait until something is checked

        let state = this.currentState;
        if (!state) {
            state = {
                theme: this.currentTheme,
                types: types,
                group: group,
                count: count,
                timer: 0,
                forceCols: colsVal,
                showAnswers: showAnswers,
                questions: this.generateQuestions(this.currentTheme, types, group, count)
            };
        } else {
            state.showAnswers = showAnswers;
            state.forceCols = colsVal;
        }

        let svg = this.createSVG(state);
        let previewWrap = this.widgetEl.querySelector('#geg-preview');
        let b64 = "data:image/svg+xml;base64," + btoa(unescape(encodeURIComponent(svg)));
        previewWrap.innerHTML = `<img src="${b64}" style="width:100%; height:100%; object-fit:contain;">`;
    },

    generateAndStamp: function () {
        let count = parseInt(this.widgetEl.querySelector('#geg-count').value);
        let timer = parseInt(this.widgetEl.querySelector('#geg-timer').value);
        let showAnswers = this.widgetEl.querySelector('#geg-show-ans').checked;
        let groupEl = this.widgetEl.querySelector('#geg-opt-group');
        let group = groupEl ? groupEl.value : 'all';
        let colsVal = this.widgetEl.querySelector('#geg-cols').value;

        let types = this.getCheckedTypes();
        if (types.length === 0) return;

        let state = this.currentState;
        if (!state) {
            state = {
                theme: this.currentTheme,
                types: types,
                group: group,
                count: count,
                timer: timer,
                forceCols: colsVal,
                showAnswers: false,
                questions: this.generateQuestions(this.currentTheme, types, group, count)
            };
        } else {
            state.showAnswers = showAnswers;
            state.timer = timer;
            state.forceCols = colsVal;
        }

        let svg = this.createSVG(state);

        if (typeof createStampFromSVG === 'function') {
            createStampFromSVG(svg, (stamp) => {
                stamp.pluginData = {
                    id: 'globalExerciseGenerator',
                    state: state
                };

                if (this.editingImgObj) {
                    this.editingImgObj.src = stamp.src;
                    this.editingImgObj.img = stamp.img; // CRITICAL FIX
                    this.editingImgObj.w = stamp.w;
                    this.editingImgObj.h = stamp.h;
                    this.editingImgObj.cw = stamp.w;
                    this.editingImgObj.ch = stamp.h;
                    this.editingImgObj.pluginData.state = state;

                    this.editingImgObj = null; // Clear edit mode
                    let btnGen = this.widgetEl.querySelector('#geg-generate');
                    if (btnGen) btnGen.innerText = "Générer et Tamponner"; // Change button back

                    if (typeof draw === 'function') draw();
                    if (typeof saveState === 'function') saveState();
                    return; // DO NOT CLOSE WIDGET
                }

                this.widgetEl.style.display = 'none'; // Only close if creating new stamp
                if (typeof setMode === 'function') setMode('globalExerciseGenerator');
                this.currentStamp = stamp;
            });
        }

        if (timer > 0) this.launchTimer(timer);
    },

    createSVG: function (state) {
        let cols = 3;
        if (state.theme === 'conj' || state.theme === 'equation' || state.theme === 'relatifs' || state.theme === 'conv') cols = 2;
        if (state.count <= 10) cols = 2;
        if (state.count > 20 && state.theme === 'math') cols = 4;

        if (state.forceCols && state.forceCols !== 'auto') {
            cols = parseInt(state.forceCols);
        }

        let rows = Math.ceil(state.count / cols);

        let cellW = 320;
        if (state.theme === 'conj') cellW = 380;
        if (state.theme === 'equation' || state.theme === 'relatifs') cellW = 320;

        let cellH = 65; // un peu plus grand pour aérer le tableau
        let paddingX = 0; // Bordure intérieure gère les marges
        let headerH = 60;

        let w = cols * cellW + paddingX * 2;
        let h = rows * cellH + headerH;

        const letters = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz";

        let themeTitles = { 'math': 'Calculs', 'relatifs': 'Nombres Relatifs', 'equation': 'Équations', 'conv': 'Conversions', 'conj': 'Conjugaison' };
        let mainTitle = themeTitles[state.theme] || "Exercices";

        let svg = `<svg xmlns="http://www.w3.org/2000/svg" class="rl-editable" data-plugin="globalExerciseGenerator" width="${w}" height="${h}" viewBox="0 0 ${w} ${h}">`;

        // Background and main outer border
        svg += `<rect x="1" y="1" width="${w - 2}" height="${h - 2}" fill="#ffffff" stroke="#2d3436" stroke-width="2"/>`;

        // Header
        svg += `<rect x="1" y="1" width="${w - 2}" height="${headerH}" fill="#2d3436"/>`;
        svg += `<text x="${w / 2}" y="${headerH / 2 + 8}" fill="#ffffff" font-family="sans-serif" font-size="24" font-weight="bold" text-anchor="middle">${mainTitle}</text>`;

        // --- NOUVEAU : Dessin de l'ŒIL magique dans le header ---
        let eyeX = w - 45;
        let eyeY = 15;
        // On dessine l'œil, si les réponses sont affichées l'œil est ouvert, sinon on peut le barrer (optionnel, on le garde simple)
        let eyeColor = state.showAnswers ? '#0984e3' : '#b2bec3';
        svg += `<g id="geg-magic-eye" transform="translate(${eyeX}, ${eyeY})">
            <rect x="-10" y="-10" width="45" height="45" fill="transparent" cursor="pointer"/> <!-- Zone de clic plus large -->
            <path d="M12 4C7 4 2.73 7.11 1 12c1.73 4.89 6 8 11 8s9.27-3.11 11-8c-1.73-4.89-6-8-11-8zm0 13c-2.76 0-5-2.24-5-5s2.24-5 5-5 5 2.24 5 5-2.24 5-5 5zm0-8c-1.66 0-3 1.34-3 3s1.34 3 3 3 3-1.34 3-3-1.34-3-3-3z" fill="${eyeColor}" transform="scale(1.2) translate(-2, -2)"/>
        </g>`;

        let yStart = headerH;

        // Lignes du quadrillage intérieur
        for (let r = 1; r < rows; r++) {
            svg += `<line x1="1" y1="${yStart + r * cellH}" x2="${w - 1}" y2="${yStart + r * cellH}" stroke="#dfe6e9" stroke-width="1.5"/>`;
        }
        for (let c = 1; c < cols; c++) {
            svg += `<line x1="${c * cellW}" y1="${yStart}" x2="${c * cellW}" y2="${h - 1}" stroke="#dfe6e9" stroke-width="1.5"/>`;
        }

        // Remplissage des cases
        for (let i = 0; i < state.questions.length; i++) {
            if (!state.questions[i]) continue;
            let c = i % cols;
            let r = Math.floor(i / cols);

            // X position inside cell
            let qx = c * cellW + 15;
            let qy = yStart + r * cellH + (cellH / 2) + 6;

            let q = state.questions[i].q;
            let a = state.questions[i].a;

            // On calcule approximativement la longueur du texte de la question pour placer la réponse juste après
            let textLenApproximation = q.length * 10 + 40; // 40 pour le "A) "

            svg += `<text x="${qx}" y="${qy}" fill="#2d3436" font-family="sans-serif" font-size="18">`;
            svg += `<tspan font-weight="bold" fill="#0984e3">${letters[i]}) </tspan>`;
            svg += `${q}`;
            svg += `</text>`;

            if (state.showAnswers && a) {
                // La réponse collée à la question
                svg += `<text x="${qx + textLenApproximation}" y="${qy}" fill="#e15f41" font-family="sans-serif" font-size="20" font-weight="bold">${a}</text>`;
            }
            // Aucun pointillé !
        }

        svg += `</svg>`;
        return svg;
    },

    launchTimer: function (m) {
        if (m <= 0) return;
        let tw = document.getElementById('time-widget');
        if (tw) {
            tw.classList.add('visible');
            let tt = document.querySelector('.tw-tab[data-tab="timer"]');
            if (tt) {
                tt.click();
                let rst = document.getElementById('btn-tw-reset');
                if (rst) rst.click();
            }

            setTimeout(() => {
                let tm = document.getElementById('tw-min');
                let ts = document.getElementById('tw-sec');
                if (tm) tm.value = m.toString().padStart(2, '0');
                if (ts) ts.value = "00";
                setTimeout(() => { let bp = document.getElementById('btn-tw-play'); if (bp) bp.click(); }, 100);
            }, 100);
        }
    },

    edit: function (imgObj) {
        this.editingImgObj = imgObj;
        let st = imgObj.pluginData.state;
        if (!st && imgObj.pluginData.args) st = imgObj.pluginData.args; // Rétro-compatibilité
        this.openWidget(st);
    },

    currentStamp: null,
    editingImgObj: null,

    onPointerDown: function (rawPos, e) {
        if (typeof mode !== 'undefined' && mode === 'globalExerciseGenerator' && this.currentStamp) {
            if (typeof images !== 'undefined') {
                images.push({
                    id: (typeof nextId !== 'undefined' ? nextId++ : Date.now()),
                    x: rawPos.x - this.currentStamp.w / 2,
                    y: rawPos.y - this.currentStamp.h / 2,
                    w: this.currentStamp.w,
                    h: this.currentStamp.h,
                    cx: 0, cy: 0,
                    cw: this.currentStamp.w,
                    ch: this.currentStamp.h,
                    src: this.currentStamp.src,
                    img: this.currentStamp.img, // Fix missing img in images array just in case
                    z: (typeof globalZ !== 'undefined' ? globalZ++ : 1),
                    pluginData: this.currentStamp.pluginData
                });
            }
            if (typeof saveState === 'function') saveState();
            if (typeof setMode === 'function') setMode('pointer');
            this.currentStamp = null;
            if (typeof draw === 'function') draw();
            return true;
        }

        if (typeof mode !== 'undefined' && mode === 'pointer' && typeof findObjectAt === 'function' && typeof getObjectById === 'function') {
            const hit = findObjectAt(rawPos.x, rawPos.y);
            if (hit && hit.type === 'image') {
                const clickedObj = getObjectById('image', hit.id);
                if (clickedObj && clickedObj.pluginData && clickedObj.pluginData.id === 'globalExerciseGenerator') {
                    let cw = clickedObj.cw || clickedObj.w;
                    let ch = clickedObj.ch || clickedObj.h;
                    // Calculate position relative to original unscaled SVG dimensions (cw, ch)
                    let localX = ((rawPos.x - clickedObj.x) / clickedObj.w) * cw;
                    let localY = ((rawPos.y - clickedObj.y) / clickedObj.h) * ch;

                    if (localX > cw - 65 && localY < 65) {
                        if (e) { e.preventDefault(); e.stopPropagation(); }
                        let st = clickedObj.pluginData.state;
                        if (!st) return false;
                        st.showAnswers = !st.showAnswers;
                        let newSvg = this.createSVG(st);
                        if (typeof createStampFromSVG === 'function') {
                            createStampFromSVG(newSvg, (newStamp) => {
                                clickedObj.src = newStamp.src;
                                clickedObj.img = newStamp.img; // CRITICAL FIX
                                clickedObj.pluginData.state = st;
                                if (typeof draw === 'function') draw();
                                if (typeof saveState === 'function') saveState();
                            });
                        }
                        return true; // We consumed the click!
                    }
                }
            }
        }
        return false;
    },

    onDraw: function (ctx) {
        if (typeof mode !== 'undefined' && mode === 'globalExerciseGenerator' && this.currentStamp && typeof mouseLogicalPos !== 'undefined' && mouseLogicalPos) {
            ctx.globalAlpha = 0.7;
            ctx.drawImage(this.currentStamp.img, mouseLogicalPos.x - this.currentStamp.w / 2, mouseLogicalPos.y - this.currentStamp.h / 2);
            ctx.globalAlpha = 1.0;
        }
    }
});

// On ajoute un écouteur global sur le document pour intercepter un clic en mode pointer
document.addEventListener('pointerdown', (e) => {
    // Si on est en mode 'pointer' (sélection normale) et qu'on clique sur le board
    if (typeof mode !== 'undefined' && mode === 'pointer' && e.target && (e.target.id === 'canvas' || e.target.id === 'board' || e.target.tagName.toLowerCase() === 'canvas')) {
        if (typeof getRawLogicalPos === 'function' && typeof findObjectAt === 'function') {
            const rawPos = getRawLogicalPos(e);
            const clickedObj = findObjectAt(rawPos.x, rawPos.y);

            // Si c'est bien une image générée par notre plugin d'exercices
            if (clickedObj && clickedObj.type === 'image' && clickedObj.pluginData && clickedObj.pluginData.id === 'globalExerciseGenerator') {

                // On calcule la position locale du clic dans l'image
                let localX = rawPos.x - clickedObj.x;
                let localY = rawPos.y - clickedObj.y;

                // La zone de clic de l'œil :
                // L'œil est dessiné en (w - 45, 15). Avec une taille de 24x24 environ.
                // On donne une zone généreuse (top right corner) : x > w - 65, y < 65
                if (localX > clickedObj.w - 65 && localY < 65) {
                    e.preventDefault();
                    e.stopPropagation();

                    // On toggle l'état "showAnswers"
                    let st = clickedObj.pluginData.state;
                    if (!st) return;
                    st.showAnswers = !st.showAnswers;

                    // On demande au plugin de regénérer le SVG
                    let plugin = PluginManager.plugins['globalExerciseGenerator'];
                    let newSvg = plugin.createSVG(st);

                    if (typeof createStampFromSVG === 'function') {
                        createStampFromSVG(newSvg, (newStamp) => {
                            clickedObj.src = newStamp.src;
                            // On garde la taille exacte du stamp, même s'il a été redimensionné via cw/ch
                            // Ou plutôt on met à jour la vraie taille de base (w, h)
                            clickedObj.w = newStamp.w;
                            clickedObj.h = newStamp.h;
                            clickedObj.pluginData.state = st;
                            if (typeof draw === 'function') draw();
                            if (typeof saveState === 'function') saveState();
                        });
                    }
                }
            }
        }
    }
});
